('Arm', '手臂', '/ɑrm/', 'She broke her arm in a skiing accident.', '她在滑雪意外中弄斷了手臂。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Hand', '手', '/hænd/', 'Please raise your hand if you have a question.', '如果有問題請舉手。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Chest', '胸部', '/tʃɛst/', 'The doctor listened to his chest with a stethoscope.', '醫生用聽診器聽他的胸部。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Back', '背部', '/bæk/', 'My back aches from sitting too long.', '我的背部因為坐太久而痠痛。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Waist', '腰部', '/weɪst/', 'The dress fits perfectly around her waist.', '這件洋裝在她的腰部非常合身。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Leg', '腿部', '/lɛg/', 'He injured his leg during the marathon.', '他在馬拉松比賽中傷到了腿部。', (SELECT id FROM categories WHERE name = '身體'), NULL),
