('Forehead', '額頭', '/ˈfɔrhɛd/', 'She wiped the sweat from her forehead.', '她擦掉額頭上的汗水。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Eyebrow', '眉毛', '/ˈaɪbraʊ/', 'He raised his eyebrow in surprise.', '他驚訝地挑起眉毛。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Eyelash', '睫毛', '/ˈaɪlæʃ/', 'She applied mascara to her eyelashes.', '她在睫毛上塗睫毛膏。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Eyelid', '眼皮', '/ˈaɪlɪd/', 'His eyelids felt heavy after staying up late.', '熬夜後他的眼皮感到沉重。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Cheek', '臉頰', '/tʃik/', 'The baby''s cheeks were rosy from the cold.', '嬰兒的臉頰因為寒冷而紅潤。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Nose', '鼻子', '/noʊz/', 'She wrinkled her nose at the bad smell.', '她因為難聞的氣味而皺起鼻子。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Nostril', '鼻孔', '/ˈnɑstrəl/', 'The doctor examined his nostrils for any blockage.', '醫生檢查他的鼻孔是否有阻塞。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Mouth', '嘴巴', '/maʊθ/', 'She opened her mouth to speak.', '她張開嘴巴要說話。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Lip', '嘴唇', '/lɪp/', 'His lips were dry from the winter air.', '他的嘴唇因為冬天的空氣而乾燥。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Chin', '下巴', '/tʃɪn/', 'He stroked his chin thoughtfully.', '他若有所思地撫摸著下巴。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Jaw', '下顎', '/dʒɔ/', 'She clenched her jaw in determination.', '她堅決地咬緊下顎。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Ear', '耳朵', '/ɪr/', 'The loud music hurt his ears.', '吵雜的音樂讓他的耳朵不舒服。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Temple', '太陽穴', '/ˈtɛmpəl/', 'She massaged her temples to relieve the headache.', '她按摩太陽穴來緩解頭痛。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Scalp', '頭皮', '/skælp/', 'A healthy scalp promotes hair growth.', '健康的頭皮促進頭髮生長。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Hair', '頭髮', '/hɛr/', 'She brushed her long hair before going out.', '她出門前梳理了長頭髮。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Beard', '鬍鬚', '/bɪrd/', 'He trimmed his beard every week.', '他每週修剪鬍鬚。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Mustache', '小鬍子', '/ˈmʌstæʃ/', 'His mustache was perfectly groomed.', '他的小鬍子修剪得很完美。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Dimple', '酒窩', '/ˈdɪmpəl/', 'Her smile revealed a cute dimple on her cheek.', '她的微笑露出臉頰上可愛的酒窩。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Wrinkle', '皺紋', '/ˈrɪŋkəl/', 'Age spots and wrinkles are signs of aging.', '老人斑和皺紋是衰老的跡象。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Breast', '乳房', '/brɛst/', 'Regular breast examinations are important for women''s health.', '定期乳房檢查對女性健康很重要。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Stomach', '胃部/腹部', '/ˈstʌmək/', 'Her stomach rumbled because she was hungry.', '她的胃部因為飢餓而咕嚕作響。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Abdomen', '腹部', '/ˈæbdəmən/', 'The doctor pressed gently on his abdomen.', '醫生輕壓他的腹部。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Hip', '臀部', '/hɪp/', 'She placed her hands on her hips and sighed.', '她把手放在臀部上嘆了口氣。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Buttocks', '臀部', '/ˈbʌtəks/', 'Sitting for long periods can cause buttocks numbness.', '長時間坐著會導致臀部麻木。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Lower back', '下背部', '/ˈloʊər bæk/', 'Many office workers suffer from lower back pain.', '許多上班族都有下背部疼痛的問題。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Side', '側邊', '/saɪd/', 'He felt a sharp pain in his side after running.', '跑步後他感到側邊一陣劇痛。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Rib', '肋骨', '/rɪb/', 'The doctor examined his ribs for any fractures.', '醫生檢查他的肋骨是否有骨折。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Navel', '肚臍', '/ˈneɪvəl/', 'The navel is also called the belly button.', '肚臍也被稱為肚臍眼。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Spine', '脊椎', '/spaɪn/', 'Good posture keeps your spine aligned.', '良好的姿勢保持脊椎對齊。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Shoulder blade', '肩胛骨', '/ˈʃoʊldər bleɪd/', 'Tension often builds up around the shoulder blades.', '緊張感經常在肩胛骨周圍累積。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Upper arm', '上臂', '/ˈʌpər ɑrm/', 'The vaccination is usually given in the upper arm.', '疫苗通常注射在上臂。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Elbow', '手肘', '/ˈɛlboʊ/', 'He bumped his elbow against the door frame.', '他的手肘撞到了門框。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Forearm', '前臂', '/ˈfɔrɑrm/', 'The tennis player had strong forearm muscles.', '這位網球選手有強壯的前臂肌肉。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Wrist', '手腕', '/rɪst/', 'She wore a beautiful bracelet around her wrist.', '她的手腕上戴著一個美麗的手鐲。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Palm', '手掌', '/pɑm/', 'He held the small bird in his palm.', '他把小鳥捧在手掌中。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Finger', '手指', '/ˈfɪŋgər/', 'She pointed with her index finger.', '她用食指指著。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Thumb', '拇指', '/θʌm/', 'He gave a thumbs up with his thumb.', '他用拇指比了個讚。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Knuckle', '指關節', '/ˈnʌkəl/', 'He cracked his knuckles before typing.', '他在打字前活動了指關節。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Fingernail', '指甲', '/ˈfɪŋgərneɪl/', 'She painted her fingernails bright red.', '她把指甲塗成鮮紅色。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Thigh', '大腿', '/θaɪ/', 'The runner felt pain in his thigh muscle.', '跑者感到大腿肌肉疼痛。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Knee', '膝蓋', '/ni/', 'She scraped her knee when she fell.', '她跌倒時擦傷了膝蓋。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Kneecap', '膝蓋骨', '/ˈnikæp/', 'The X-ray showed a fracture in the kneecap.', 'X光顯示膝蓋骨有骨折。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Shin', '小腿前側', '/ʃɪn/', 'He kicked the ball with his shin by accident.', '他意外地用小腿前側踢到球。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Calf', '小腿肚', '/kæf/', 'Her calf muscles cramped after the long run.', '長跑後她的小腿肚肌肉抽筋。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Ankle', '腳踝', '/ˈæŋkəl/', 'She twisted her ankle while hiking.', '她在健行時扭到了腳踝。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Heel', '腳跟', '/hil/', 'The new shoes gave her blisters on her heels.', '新鞋子讓她的腳跟起了水泡。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Toe', '腳趾', '/toʊ/', 'He stubbed his toe on the table leg.', '他的腳趾撞到了桌腳。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Big toe', '大腳趾', '/bɪg toʊ/', 'The doctor examined his infected big toe.', '醫生檢查他感染的大腳趾。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Toenail', '腳趾甲', '/ˈtoʊneɪl/', 'She trimmed her toenails before going to the beach.', '她在去海灘前修剪了腳趾甲。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Lungs', '肺部', '/lʌŋz/', 'The lungs exchange oxygen and carbon dioxide.', '肺部進行氧氣和二氧化碳的交換。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Trachea', '氣管', '/ˈtreɪkiə/', 'The trachea carries air to and from the lungs.', '氣管將空氣輸送到肺部和從肺部輸送出來。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Bronchi', '支氣管', '/ˈbrɑŋkaɪ/', 'The bronchi branch into smaller airways in the lungs.', '支氣管在肺部分支成更小的氣道。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Diaphragm', '橫膈膜', '/ˈdaɪəfræm/', 'The diaphragm is the main muscle used for breathing.', '橫膈膜是呼吸時使用的主要肌肉。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Liver', '肝臟', '/ˈlɪvər/', 'The liver filters toxins from the blood.', '肝臟過濾血液中的毒素。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Small intestine', '小腸', '/smɔl ɪnˈtɛstən/', 'The small intestine absorbs nutrients from food.', '小腸吸收食物中的營養。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Large intestine', '大腸', '/lɑrdʒ ɪnˈtɛstən/', 'The large intestine processes waste before elimination.', '大腸在排泄前處理廢物。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Pancreas', '胰臟', '/ˈpæŋkriəs/', 'The pancreas produces insulin and digestive enzymes.', '胰臟產生胰島素和消化酵素。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Gallbladder', '膽囊', '/ˈgɔlblædər/', 'The gallbladder stores bile produced by the liver.', '膽囊儲存肝臟產生的膽汁。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Esophagus', '食道', '/ɪˈsɑfəgəs/', 'Food travels down the esophagus to reach the stomach.', '食物通過食道到達胃部。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Heart', '心臟', '/hɑrt/', 'The heart pumps blood throughout the body.', '心臟將血液輸送到全身。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Artery', '動脈', '/ˈɑrtəri/', 'The artery carries oxygenated blood from the heart.', '動脈運送含氧血液離開心臟。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Vein', '靜脈', '/veɪn/', 'The vein returns deoxygenated blood to the heart.', '靜脈將缺氧血液送回心臟。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Capillary', '微血管', '/ˈkæpəlɛri/', 'Capillaries connect arteries and veins.', '微血管連接動脈和靜脈。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Aorta', '主動脈', '/eɪˈɔrtə/', 'The aorta is the largest artery in the body.', '主動脈是人體最大的動脈。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Kidney', '腎臟', '/ˈkɪdni/', 'The kidneys filter waste from the blood.', '腎臟過濾血液中的廢物。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Bladder', '膀胱', '/ˈblædər/', 'The bladder stores urine until it''s released.', '膀胱儲存尿液直到排出。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Ureter', '輸尿管', '/jʊˈritər/', 'The ureter carries urine from kidney to bladder.', '輸尿管將尿液從腎臟輸送到膀胱。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Urethra', '尿道', '/jʊˈriθrə/', 'Urine exits the body through the urethra.', '尿液通過尿道排出體外。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Spleen', '脾臟', '/splin/', 'The spleen filters blood and supports immune function.', '脾臟過濾血液並支持免疫功能。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Bone', '骨頭', '/boʊn/', 'The X-ray showed a crack in the bone.', 'X光顯示骨頭有裂縫。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Joint', '關節', '/dʒɔɪnt/', 'His knee joint was swollen after the injury.', '受傷後他的膝關節腫脹。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Cartilage', '軟骨', '/ˈkɑrtəlɪdʒ/', 'The cartilage in his knee was damaged.', '他膝蓋的軟骨受損了。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Ligament', '韌帶', '/ˈlɪgəmənt/', 'She tore her ligament playing soccer.', '她踢足球時撕裂了韌帶。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Tendon', '肌腱', '/ˈtɛndən/', 'The Achilles tendon connects the calf muscle to the heel.', '阿基里斯肌腱連接小腿肌肉和腳跟。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Muscle', '肌肉', '/ˈmʌsəl/', 'Regular exercise strengthens your muscles.', '定期運動能強化你的肌肉。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Vertebra', '脊椎骨', '/ˈvɜrtəbrə/', 'The doctor pointed to the damaged vertebra on the scan.', '醫生指著掃描影像上受損的脊椎骨。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Disc', '椎間盤', '/dɪsk/', 'A herniated disc can cause severe back pain.', '椎間盤突出會導致嚴重的背痛。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Marrow', '骨髓', '/ˈmæroʊ/', 'Bone marrow produces blood cells.', '骨髓製造血球細胞。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Socket', '關節窩', '/ˈsɑkət/', 'The shoulder socket allows for a wide range of motion.', '肩膀關節窩允許大幅度的活動。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Fracture', '骨折', '/ˈfræktʃər/', 'The fracture will take six weeks to heal.', '這個骨折需要六週才能癒合。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Dislocation', '脫臼', '/ˌdɪsloʊˈkeɪʃən/', 'The dislocation of his shoulder was very painful.', '他肩膀脫臼非常疼痛。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Blood', '血液', '/blʌd/', 'The doctor took a blood sample for testing.', '醫生抽取血液樣本進行檢驗。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Plasma', '血漿', '/ˈplæzmə/', 'Plasma makes up about 55% of blood volume.', '血漿約佔血液總體積的55%。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Saliva', '唾液', '/səˈlaɪvə/', 'Saliva helps digest food and keeps the mouth moist.', '唾液幫助消化食物並保持口腔濕潤。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Tears', '眼淚', '/tɪrz/', 'Tears protect the eyes from dust and bacteria.', '眼淚保護眼睛免受灰塵和細菌侵害。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Sweat', '汗水', '/swɛt/', 'Exercise causes the body to produce sweat.', '運動會讓身體產生汗水。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Urine', '尿液', '/ˈjʊrən/', 'The urine test showed no signs of infection.', '尿液檢查顯示沒有感染跡象。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Bile', '膽汁', '/baɪl/', 'Bile helps digest fats in the small intestine.', '膽汁幫助在小腸中消化脂肪。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Mucus', '黏液', '/ˈmjukəs/', 'The nose produces mucus to trap particles.', '鼻子產生黏液來捕捉顆粒。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Lymph', '淋巴液', '/lɪmf/', 'Lymph carries white blood cells throughout the body.', '淋巴液將白血球輸送到全身。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Cerebrospinal fluid', '腦脊髓液', '/ˌsɛrəbroʊˈspaɪnəl ˈfluɪd/', 'Cerebrospinal fluid protects the brain and spinal cord.', '腦脊髓液保護大腦和脊髓。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Synovial fluid', '關節滑液', '/sɪˈnoʊviəl ˈfluɪd/', 'Synovial fluid lubricates the joints.', '關節滑液潤滑關節。', (SELECT id FROM categories WHERE name = '身體'), NULL),
('Gastric juice', '胃液', '/ˈgæstrɪk dʒus/', 'Gastric juice contains acids that break down food.', '胃液含有分解食物的酸性物質。', (SELECT id FROM categories WHERE name = '身體'), NULL);
INSERT INTO vocabularies (english, chinese, phonetic, example_en, example_cn, category_id, image) VALUES
('shirt', '襯衫', '/ʃɜːrt/', 'Dad wears a white shirt.', '爸爸穿白襯衫。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('pants', '褲子', '/pænts/', 'These pants are too long.', '這條褲子太長了。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('dress', '洋裝', '/dres/', 'She has a beautiful dress.', '她有一件漂亮的洋裝。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('shoes', '鞋子', '/ʃuːz/', 'My shoes are black.', '我的鞋子是黑色的。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('socks', '襪子', '/sɑːks/', 'I need clean socks.', '我需要乾淨的襪子。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('hat', '帽子', '/hæt/', 'The hat keeps me warm.', '帽子讓我保暖。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('coat', '外套', '/koʊt/', 'It''s cold, wear your coat.', '天氣冷，穿上外套。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('skirt', '裙子', '/skɜːrt/', 'The skirt is red.', '裙子是紅色的。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('jacket', '夾克', '/ˈdʒækɪt/', 'My jacket has pockets.', '我的夾克有口袋。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('tie', '領帶', '/taɪ/', 'Father wears a tie to work.', '爸爸工作時打領帶。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('T-shirt', 'T恤、短袖上衣', '/ˈtiː.ʃɜːt/', 'I always wear a comfortable T-shirt when I go to the gym.', '我去健身房時總是穿舒適的T恤。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Hoodie', '連帽上衣、帽T', '/ˈhʊd.i/', 'She put on her favorite hoodie before heading out in the cold morning.', '她在寒冷的早晨出門前穿上最愛的連帽上衣。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Polo shirt', 'Polo衫、有領短袖衫', '/ˈpoʊ.loʊ ʃɜːrt/', 'The polo shirt is perfect for casual business meetings.', '這件Polo衫很適合非正式的商務會議。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Tank top', '背心、無袖上衣', '/tæŋk tɑːp/', 'During summer, a tank top keeps you cool and comfortable.', '夏天時，背心能讓你保持涼爽舒適。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Sweatshirt', '運動衫、衛衣', '/ˈswet.ʃɜːrt/', 'He wore a thick sweatshirt after his morning workout.', '他在晨練後穿上厚厚的運動衫。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Long-sleeve', '長袖上衣', '/lɔːŋ sliːv/', 'A long-sleeve shirt is ideal for spring weather.', '長袖襯衫是春季的理想選擇。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Blouse', '女式襯衫、罩衫', '/blaʊs/', 'The silk blouse added elegance to her business outfit.', '這件絲質女式襯衫為她的商務裝增添了優雅感。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Cardigan', '開襟衫、羊毛衫', '/ˈkɑːr.dɪ.ɡən/', 'She layered a soft cardigan over her dress for extra warmth.', '她在洋裝外面加了一件柔軟的開襟衫來保暖。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Tunic', '長上衣、束腰外衣', '/ˈtuː.nɪk/', 'The flowing tunic paired beautifully with her favorite leggings.', '這件飄逸的長上衣與她最愛的緊身褲搭配得很好。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Button-up', '鈕扣襯衫', '/ˈbʌt.ən ʌp/', 'He chose a navy button-up for the important presentation.', '他為重要的簡報選擇了一件深藍色鈕扣襯衫。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Dress shirt', '正裝襯衫', '/dres ʃɜːrt/', 'Every man needs at least three white dress shirts.', '每個男人至少需要三件白色正裝襯衫。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Oxford shirt', '牛津襯衫', '/ˈɑːks.fɚd ʃɜːrt/', 'An Oxford shirt with chinos is a timeless preppy look.', '牛津襯衫搭配卡其褲是永恆的學院風造型。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Sweater', '毛衣、針織衫', '/ˈswet.ər/', 'The wool sweater kept him warm during the winter hike.', '這件羊毛毛衣在冬季健行時讓他保持溫暖。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Pullover', '套頭毛衣、套頭衫', '/ˈpʊl.oʊ.vər/', 'The cashmere pullover felt incredibly soft against her skin.', '這件羊絨套頭毛衣觸感非常柔軟。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Jumper', '毛衣（英式英語）', '/ˈdʒʌm.pər/', 'She knitted a beautiful jumper with intricate patterns.', '她編織了一件有精美圖案的毛衣。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Vest', '背心、馬甲', '/vest/', 'The formal vest completed his three-piece suit perfectly.', '這件正式的背心完美地搭配了他的三件式西裝。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Turtleneck', '高領毛衣', '/ˈtɜːr.t̬əl.nek/', 'A black turtleneck is both stylish and practical for autumn weather.', '黑色高領毛衣既時尚又適合秋天的天氣。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Knitwear', '針織服裝', '/ˈnɪt.wer/', 'Their winter collection features luxury knitwear.', '他們的冬季系列以奢華針織服裝為特色。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Cable knit', '麻花針織', '/ˈkeɪ.bəl nɪt/', 'The cable knit sweater is a classic winter staple.', '麻花針織毛衣是經典的冬季基本款。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Trousers', '褲子（英式英語）', '/ˈtraʊ.zərz/', 'He pressed his trousers before the important interview.', '他在重要面試前熨燙了褲子。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Jeans', '牛仔褲', '/dʒiːnz/', 'A pair of well-fitted jeans is a wardrobe staple for casual wear.', '一條合身的牛仔褲是休閒穿搭的基本單品。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Leggings', '緊身褲、內搭褲', '/ˈleɡ.ɪŋz/', 'Athletic leggings provide both comfort and flexibility during yoga.', '運動緊身褲在瑜伽時提供舒適性和靈活性。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Chinos', '卡其褲、休閒長褲', '/ˈtʃiː.noʊz/', 'Beige chinos offer a smart-casual look for weekend outings.', '米色卡其褲為週末外出提供了時尚休閒的造型。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Trunks', '運動短褲、體育短褲', '/trʌŋk/', 'John needs to wear trunks when playing basketball.', 'John打籃球時需要穿運動短褲。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Swimming trunks', '男式泳褲', '/ˈswɪm.ɪŋ trʌŋk/', 'Harry bought three swimming trunks before going to the beach.', '哈利Harry在去海邊前買了三條泳褲。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Shorts', '短褲', '/ʃɔːrts/', 'Cotton shorts are ideal for hot summer days at the beach.', '棉質短褲很適合在海邊的炎熱夏日穿著。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Mini skirt', '迷你裙、短裙', '/ˈmɪn.i skɜːrt/', 'The denim mini skirt paired well with her ankle boots.', '這件牛仔迷你裙與她的短靴搭配得很好。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Maxi dress', '長洋裝、拖地裙', '/ˈmæk.si dres/', 'The flowing maxi dress was perfect for the beach wedding.', '這件飄逸的長洋裝很適合海邊婚禮。', (SELECT id FROM categories WHERE name = '服飾'), NULL),
('Evening dress', '晚禮服、晚宴禮服', '/ˈiːv.nɪŋ dres/', 'Anna''s evening dress is very expensive but absolutely stunning. ( 
