('cat', '貓', '/kæt/', 'The cat likes to sleep.', '貓喜歡睡覺。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('dog', '狗', '/dɔːɡ/', 'My dog can sit and stay.', '我的狗會坐下和待著。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('bird', '鳥', '/bɜːrd/', 'The bird flies in the sky.', '鳥在天空中飛翔。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('fish', '魚', '/fɪʃ/', 'Fish live in water.', '魚生活在水中。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('cow', '牛', '/kaʊ/', 'The cow gives us milk.', '牛給我們牛奶。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('pig', '豬', '/pɪɡ/', 'The pig is pink.', '豬是粉紅色的。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('horse', '馬', '/hɔːrs/', 'The horse runs fast.', '馬跑得很快。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('rabbit', '兔子', '/ˈræbɪt/', 'The rabbit has long ears.', '兔子有長耳朵。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('duck', '鴨子', '/dʌk/', 'The duck swims in the pond.', '鴨子在池塘裡游泳。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('chicken', '雞', '/ˈtʃɪkɪn/', 'The chicken lays eggs.', '雞會下蛋。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('hamster', '倉鼠', '/ˈhæmstɚ/', 'The hamster runs on its wheel for hours every night.', '倉鼠每晚在滾輪上跑數小時。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('goldfish', '金魚', '/ˈgoʊldˌfɪʃ/', 'She feeds her goldfish twice a day with special fish food.', '她每天用專用魚食餵金魚兩次。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('parrot', '鸚鵡', '/ˈpærət/', 'The colorful parrot can mimic human speech perfectly.', '這隻色彩鮮豔的鸚鵡能完美地模仿人類說話。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('guinea pig', '天竺鼠', '/ˈgɪni pɪg/', 'The guinea pig squeaks happily when it sees fresh vegetables.', '天竺鼠看到新鮮蔬菜時會開心地吱吱叫。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('turtle', '烏龜', '/ˈtɝtl/', 'The pet turtle moves slowly across the terrarium floor.', '寵物烏龜在玻璃箱底部緩慢爬行。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('ferret', '雪貂', '/ˈfɛrət/', 'The playful ferret explores every corner of the house curiously.', '頑皮的雪貂好奇地探索房子的每個角落。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('chinchilla', '龍貓', '/tʃɪnˈtʃɪlə/', 'The soft chinchilla takes dust baths to keep its fur clean.', '柔軟的龍貓洗沙浴來保持毛髮清潔。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('canary', '金絲雀', '/kəˈnɛri/', 'The yellow canary sings melodiously every morning at sunrise.', '黃色的金絲雀每天日出時悅耳地歌唱。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('budgie', '虎皮鸚鵡', '/ˈbʌdʒi/', 'The colorful budgie chatters constantly with its cage mate.', '色彩繽紛的虎皮鸚鵡與籠友不停地聊天。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('gecko', '壁虎', '/ˈgɛkoʊ/', 'The small gecko climbs effortlessly up the glass terrarium wall.', '小壁虎毫不費力地爬上玻璃箱壁。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('hedgehog', '刺蝟', '/ˈhɛdʒˌhɔg/', 'The hedgehog rolls into a spiky ball when feeling threatened.', '刺蝟在感到威脅時會蜷縮成帶刺的球。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('iguana', '鬣蜥', '/ɪˈgwɑnə/', 'The large iguana basks under the heat lamp for several hours daily.', '大鬣蜥每天在加熱燈下曬太陽數小時。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('sheep', '綿羊', '/ʃip/', 'Each sheep provides wool for making warm winter clothing.', '每隻綿羊都提供羊毛來製作溫暖的冬衣。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('goose', '鵝', '/gus/', 'The goose honks loudly to protect its young goslings.', '鵝大聲鳴叫來保護牠的小鵝。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('goat', '山羊', '/goʊt/', 'The goat climbs steep rocky hills with remarkable agility.', '山羊以驚人的敏捷性爬上陡峭的岩石山丘。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('turkey', '火雞', '/ˈtɝki/', 'The turkey spreads its colorful feathers during mating season.', '火雞在交配季節展開牠色彩豐富的羽毛。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('rooster', '公雞', '/ˈrustɚ/', 'The rooster crows loudly at sunrise every morning.', '公雞每天早晨在日出時大聲啼叫。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('bull', '公牛', '/bʊl/', 'The powerful bull paws the ground before charging forward.', '強壯的公牛在衝鋒前用蹄子刨地。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('ox', '閹牛', '/ɑks/', 'The ox pulls the heavy plow through the muddy field.', '閹牛拖著重犁穿過泥濘的田地。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('lamb', '小羊', '/læm/', 'The innocent lamb follows its mother closely in the pasture.', '純真的小羊在牧場上緊跟著媽媽。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('ram', '公羊', '/ræm/', 'The ram uses its curved horns to establish dominance in the flock.', '公羊用彎曲的角在羊群中建立統治地位。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('hen', '母雞', '/hɛn/', 'The hen protects her chicks from potential predators.', '母雞保護小雞免受潛在掠食者的傷害。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('chick', '小雞', '/tʃɪk/', 'The fluffy chick pecks at grain scattered on the ground.', '毛茸茸的小雞啄食散落在地上的穀物。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('donkey', '驢子', '/ˈdɔŋki/', 'The stubborn donkey carries heavy loads up mountain paths.', '頑固的驢子背著重物走上山路。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('mule', '騾子', '/mjul/', 'The hardy mule works tirelessly in harsh desert conditions.', '堅韌的騾子在惡劣的沙漠環境中不知疲倦地工作。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('lion', '獅子', '/ˈlaɪən/', 'The powerful lion roars majestically across the African savanna.', '強壯的獅子在非洲大草原上威嚴地咆哮。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('tiger', '老虎', '/ˈtaɪgɚ/', 'The tiger hunts silently through dense jungle undergrowth.', '老虎在茂密的叢林下層植物中無聲地狩獵。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('elephant', '大象', '/ˈɛləfənt/', 'The gentle elephant uses its trunk to gather food and water.', '溫和的大象用牠的象鼻收集食物和水。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('giraffe', '長頸鹿', '/dʒəˈræf/', 'The tall giraffe stretches its neck to reach leaves on high branches.', '高大的長頸鹿伸長脖子去夠高樹枝上的葉子。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('bear', '熊', '/bɛr/', 'The bear hibernates peacefully during the cold winter months.', '熊在寒冷的冬季月份中安靜地冬眠。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('wolf', '狼', '/wʊlf/', 'The wolf howls hauntingly under the bright full moon.', '狼在明亮的滿月下淒厲地嚎叫。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('fox', '狐狸', '/fɑks/', 'The clever fox outsmarts hunters with its cunning strategies.', '聰明的狐狸用牠狡猾的策略智勝獵人。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('deer', '鹿', '/dɪr/', 'The graceful deer leaps elegantly through the forest clearing.', '優雅的鹿在森林空地中優美地跳躍。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('zebra', '斑馬', '/ˈzibrə/', 'The zebra displays distinctive black and white stripes for protection.', '斑馬展示獨特的黑白條紋以獲得保護。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('kangaroo', '袋鼠', '/ˌkæŋgəˈru/', 'The kangaroo hops across the Australian outback with powerful legs.', '袋鼠用強壯的腿在澳洲內陸跳躍。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('koala', '無尾熊', '/koʊˈɑlə/', 'The sleepy koala clings to eucalyptus trees for most of the day.', '昏昏欲睡的無尾熊一天中大部分時間都抱著桉樹。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('panda', '熊貓', '/ˈpændə/', 'The adorable panda munches bamboo shoots peacefully in the forest.', '可愛的熊貓在森林裡安靜地咀嚼竹筍。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('monkey', '猴子', '/ˈmʌŋki/', 'The playful monkey swings from branch to branch with ease.', '頑皮的猴子輕鬆地從一根樹枝盪到另一根。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('rhinoceros', '犀牛', '/raɪˈnɑsərəs/', 'The massive rhinoceros charges through the grassland with tremendous force.', '巨大的犀牛以強大的力量衝過草原。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('hippopotamus', '河馬', '/ˌhɪpəˈpɑtəməs/', 'The hippopotamus spends most of its time submerged in river water.', '河馬大部分時間都浸泡在河水中。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('cheetah', '獵豹', '/ˈtʃitə/', 'The cheetah runs at incredible speeds across the open grassland.', '獵豹在開闊草原上以驚人速度奔跑。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('leopard', '花豹', '/ˈlɛpərd/', 'The spotted leopard hunts silently in the darkness of night.', '有斑點的花豹在黑夜中無聲地狩獵。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('panther', '黑豹', '/ˈpænθɚ/', 'The sleek panther moves stealthily through dense jungle foliage.', '光滑的黑豹在茂密的叢林樹葉間隱秘地移動。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('jaguar', '美洲豹', '/ˈdʒægjuɚ/', 'The powerful jaguar has the strongest bite of all big cats.', '強壯的美洲豹擁有所有大型貓科動物中最強的咬合力。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('lynx', '猞猁', '/lɪŋks/', 'The lynx has distinctive tufted ears and a short bobbed tail.', '猞猁有獨特的毛簇耳朵和短截尾巴。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('bobcat', '短尾貓', '/ˈbɑbˌkæt/', 'The bobcat is an excellent climber and swimmer.', '短尾貓是出色的攀爬者和游泳者。', (SELECT id FROM categories WHERE name = '動物'), NULL),
