('cockroach', '蟑螂', '/ˈkɑkˌroʊtʃ/', 'The resilient cockroach can survive in harsh conditions.', '有韌性的蟑螂能在惡劣條件下生存。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('grasshopper', '蚱蜢', '/ˈgræsˌhɑpɚ/', 'The grasshopper leaps great distances with powerful hind legs.', '蚱蜢用強有力的後腿跳躍很遠的距離。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('cricket', '蟋蟀', '/ˈkrɪkət/', 'The cricket chirps melodiously on warm summer nights.', '蟋蟀在溫暖的夏夜悅耳地鳴叫。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('locust', '蝗蟲', '/ˈloʊkəst/', 'The locust swarms can devastate entire crop fields.', '蝗蟲群能摧毀整片農田。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('mosquito', '蚊子', '/məˈskitoʊ/', 'The annoying mosquito buzzes around during summer evenings.', '惱人的蚊子在夏天傍晚嗡嗡飛舞。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('fly', '蒼蠅', '/flaɪ/', 'The persistent fly circles around food sources.', '頑固的蒼蠅圍繞食物來源飛舞。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('dragonfly', '蜻蜓', '/ˈdrægənˌflaɪ/', 'The dragonfly hovers gracefully above the pond water.', '蜻蜓在池水上方優雅地盤旋。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('damselfly', '豆娘', '/ˈdæməlˌflaɪ/', 'The delicate damselfly folds its wings when at rest.', '纖細的豆娘在休息時會摺疊翅膀。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('firefly', '螢火蟲', '/ˈfaɪɚˌflaɪ/', 'The firefly creates magical light displays on summer nights.', '螢火蟲在夏夜創造魔幻的光影表演。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('ladybug', '瓢蟲', '/ˈleɪdiˌbʌg/', 'The spotted ladybug feeds on garden pests like aphids.', '有斑點的瓢蟲以蚜蟲等花園害蟲為食。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('beetle', '甲蟲', '/ˈbitəl/', 'The beetle has hard wing covers protecting its flight wings.', '甲蟲有堅硬的翅鞘保護飛行翅膀。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('caterpillar', '毛毛蟲', '/ˈkætɚˌpɪlɚ/', 'The caterpillar transforms into a beautiful butterfly.', '毛毛蟲變成美麗的蝴蝶。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('larva', '幼蟲', '/ˈlɑrvə/', 'The larva develops inside a protective cocoon.', '幼蟲在保護性的繭中發育。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('orangutan', '紅毛猩猩', '/ɔˈræŋəˌtæn/', 'The intelligent orangutan swings through rainforest canopies.', '聰明的紅毛猩猩在雨林樹冠間擺盪。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('gorilla', '大猩猩', '/gəˈrɪlə/', 'The mountain gorilla is critically endangered in the wild.', '山地大猩猩在野外瀕臨絕種。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('chimpanzee', '黑猩猩', '/ˌtʃɪmpænˈzi/', 'The chimpanzee shares 98% of its DNA with humans.', '黑猩猩與人類共享98%的DNA。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('snow leopard', '雪豹', '/snoʊ ˈlɛpərd/', 'The elusive snow leopard inhabits high mountain regions.', '難以捉摸的雪豹棲息在高山地區。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('polar bear', '北極熊', '/ˈpoʊlɚ bɛr/', 'The polar bear depends on sea ice for hunting seals.', '北極熊依賴海冰獵捕海豹。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('blue whale', '藍鯨', '/blu hweɪl/', 'The blue whale is the largest animal ever known to exist.', '藍鯨是已知存在過的最大動物。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('sea turtle', '海龜', '/si ˈtɝtl/', 'The sea turtle returns to its birth beach to lay eggs.', '海龜回到出生海灘產卵。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('manatee', '海牛', '/ˈmænəˌti/', 'The gentle manatee grazes on seagrass in warm waters.', '溫和的海牛在溫暖水域中吃海草。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('condor', '禿鷹', '/ˈkɑndɚ/', 'The California condor has been saved from extinction.', '加州禿鷹已從滅絕邊緣被拯救。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('albatross', '信天翁', '/ˈælbəˌtrɔs/', 'The wandering albatross has the largest wingspan of any bird.', '漂泊信天翁有所有鳥類中最大的翼展。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('pangolin', '穿山甲', '/ˈpæŋgəlɪn/', 'The pangolin is the world''s most trafficked mammal.', '穿山甲是世界上被非法交易最多的哺乳動物。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('lemur', '狐猴', '/ˈlimɚ/', 'The ring-tailed lemur is endemic to Madagascar.', '環尾狐猴是馬達加斯加特有種。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('bark', '吠叫', '/bɑrk/', 'The dog barks loudly when strangers approach the house.', '狗在陌生人接近房子時大聲吠叫。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('meow', '貓叫', '/miˈaʊ/', 'The hungry cat meows persistently for its dinner.', '飢餓的貓為了晚餐持續地貓叫。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('roar', '咆哮', '/rɔr/', 'The lion roars to establish dominance over its territory.', '獅子咆哮來建立對其領域的統治地位。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('howl', '嚎叫', '/haʊl/', 'Wolves howl to communicate with distant pack members.', '狼嚎叫來與遠處的群體成員交流。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('chirp', '啁啾', '/tʃɝp/', 'Small birds chirp melodiously at the break of dawn.', '小鳥在黎明時分悅耳地啁啾。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('buzz', '嗡嗡聲', '/bʌz/', 'Bees buzz busily around the blooming flowers.', '蜜蜂在盛開的花朵周圍忙碌地嗡嗡響。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('hiss', '嘶嘶聲', '/hɪs/', 'The snake hisses as a warning when feeling threatened.', '蛇在感到威脅時發出嘶嘶聲作為警告。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('trumpet', '象鳴', '/ˈtrʌmpɪt/', 'Elephants trumpet to communicate across long distances.', '大象發出象鳴聲來進行長距離交流。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('croak', '呱呱叫', '/kroʊk/', 'Frogs croak loudly during humid summer nights.', '青蛙在潮濕的夏夜大聲呱呱叫。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('squeak', '吱吱聲', '/skwik/', 'Mice squeak when they sense danger nearby.', '老鼠在感覺到附近有危險時會吱吱叫。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('puppy', '小狗', '/ˈpʌpi/', 'The adorable puppy plays with its colorful toys enthusiastically.', '可愛的小狗熱情地玩牠色彩繽紛的玩具。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('kitten', '小貓', '/ˈkɪtən/', 'The tiny kitten purrs contentedly in its mother''s arms.', '小貓在媽媽懷裡滿足地呼嚕聲。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('cub', '幼獸(熊/獅)', '/kʌb/', 'The lion cub learns hunting skills by watching its parents.', '獅子幼崽通過觀察父母學習狩獵技巧。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('duckling', '小鴨子', '/ˈdʌklɪŋ/', 'The duckling swims behind its mother in a perfect line.', '小鴨子排成完美的一列跟在媽媽後面游泳。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('foal', '小馬駒', '/foʊl/', 'The foal takes its first wobbly steps in the stable.', '小馬駒在馬廄裡邁出牠搖搖擺擺的第一步。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('calf', '小牛犢', '/kæf/', 'The calf nurses from its mother several times daily.', '小牛犢每天從媽媽那裡哺乳數次。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('fawn', '小鹿', '/fɔn/', 'The spotted fawn hides quietly in the tall forest grass.', '有斑點的小鹿安靜地躲在高高的森林草叢中。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('joey', '小袋鼠', '/ˈdʒoʊi/', 'The joey peeks out from its mother''s protective pouch.', '小袋鼠從媽媽的保護袋中偷看。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('a pride of lions', '一群獅子', '/praɪd/', 'A pride of lions dominates the vast African savanna territory.', '一群獅子統治著廣闊的非洲大草原領域。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('a pack of wolves', '一群狼', '/pæk/', 'A pack of wolves hunts cooperatively during winter months.', '一群狼在冬季月份中合作狩獵。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('a school of fish', '一群魚', '/skul/', 'A school of fish swims in perfect synchronization underwater.', '一群魚在水下完美同步地游泳。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('a flock of birds', '一群鳥', '/flɑk/', 'A flock of birds migrates south before winter arrives.', '一群鳥在冬天到來之前向南遷徙。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('a herd of cattle', '一群牛', '/hɝd/', 'A herd of cattle grazes peacefully in the green pasture.', '一群牛在綠色牧場上安靜地吃草。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('a swarm of bees', '一群蜜蜂', '/swɔrm/', 'A swarm of bees protects their hive from potential threats.', '一群蜜蜂保護牠們的蜂巢免受潛在威脅。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('a pod of whales', '一群鯨魚', '/pɑd/', 'A pod of whales travels together across ocean depths.', '一群鯨魚一起穿越海洋深處。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('a gaggle of geese', '一群鵝', '/ˈgægəl/', 'A gaggle of geese honks loudly while flying overhead.', '一群鵝在頭頂飛過時大聲鳴叫。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('a colony of ants', '一群螞蟻', '/ˈkɑləni/', 'A colony of ants works tirelessly to build their underground home.', '一群螞蟻不知疲倦地工作來建造牠們的地下家園。', (SELECT id FROM categories WHERE name = '動物'), NULL),
('a murder of crows', '一群烏鴉', '/ˈmɝdɚ/', 'A murder of crows gathers ominously in the dead tree.', '一群烏鴉不祥地聚集在枯樹上。', (SELECT id FROM categories WHERE name = '動物'), NULL);
INSERT INTO vocabularies (english, chinese, phonetic, example_en, example_cn, category_id, image) VALUES
('table', '桌子', '/ˈteɪbəl/', 'We eat dinner at the table.', '我們在桌子上吃晚餐。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL),
('chair', '椅子', '/tʃer/', 'Please sit on the chair.', '請坐在椅子上。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL),
('bed', '床', '/bed/', 'I sleep in my bed.', '我在床上睡覺。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL),
('door', '門', '/dɔːr/', 'Close the door, please.', '請關門。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL),
('window', '窗戶', '/ˈwɪndoʊ/', 'Look out the window.', '往窗外看。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL),
('lamp', '燈', '/læmp/', 'Turn on the lamp.', '把燈打開。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL),
('clock', '時鐘', '/klɑːk/', 'The clock shows three o''clock.', '時鐘顯示三點。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL),
('TV', '電視', '/ˌtiː ˈviː/', 'We watch TV together.', '我們一起看電視。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL),
('phone', '電話', '/foʊn/', 'Answer the phone, please.', '請接電話。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL),
('computer', '電腦', '/kəmˈpjuːtər/', 'I use the computer to study.', '我用電腦學習。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL),
('Chaise Lounge', '躺椅', '/ˌʃeɪz ˈlaʊndʒ/', 'The chaise lounge in the bedroom corner is perfect for afternoon reading.', '臥室角落的躺椅很適合午後閱讀。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL),
('Ottoman', '腳凳/收納凳', '/ˈɑtəmən/', 'This storage ottoman serves as both seating and a coffee table.', '這個收納腳凳既可以當座椅也可以當茶几。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL),
('Sectional Sofa', '組合沙發', '/ˈsɛkʃənəl ˈsoʊfə/', 'The L-shaped sectional sofa maximizes seating in our small living room.', 'L型組合沙發在我們小客廳裡最大化了座位空間。', (SELECT id FROM categories WHERE name = '家庭用品'), NULL);
INSERT INTO vocabularies (english, chinese, phonetic, example_en, example_cn, category_id, image) VALUES
('Green tea', '綠茶', '/ɡriːn tiː/', 'I prefer green tea over black tea for its lighter flavor.', '我偏好綠茶勝過紅茶，因為它的味道比較清淡。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Black tea', '紅茶', '/blæk tiː/', 'A cup of black tea with milk is perfect for afternoon break.', '一杯加牛奶的紅茶最適合下午茶時光。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Oolong tea', '烏龍茶', '/ˈuːlɒŋ tiː/', 'This oolong tea has a complex flavor profile with floral notes.', '這款烏龍茶有著複雜的風味層次，帶有花香調性。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Bubble tea', '珍珠奶茶', '/ˈbʌbl tiː/', 'Bubble tea has become increasingly popular worldwide.', '珍珠奶茶在全世界都越來越受歡迎。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('White tea', '白茶', '/waɪt tiː/', 'White tea is known for its delicate and subtle taste.', '白茶以其精緻細膩的口感而聞名。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Pu-erh tea', '普洱茶', '/puːˈɛər tiː/', 'Aged Pu-erh tea develops a rich, earthy flavor over time.', '陳年普洱茶會隨時間發展出豐富的土壤風味。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Jasmine tea', '茉莉花茶', '/ˈdʒæzmɪn tiː/', 'Jasmine tea combines green tea with fragrant jasmine blossoms.', '茉莉花茶結合了綠茶與芬芳的茉莉花。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Earl Grey', '伯爵茶', '/ɜːl ɡreɪ/', 'Earl Grey tea is flavored with bergamot oil for a citrusy aroma.', '伯爵茶加入佛手柑油調味，帶有柑橘香氣。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Chamomile tea', '洋甘菊茶', '/ˈkæməmaɪl tiː/', 'Chamomile tea is often enjoyed before bedtime for its calming properties.', '洋甘菊茶常在睡前飲用，因其有鎮靜效果。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Matcha', '抹茶', '/ˈmætʃə/', 'Traditional matcha ceremony requires precise preparation techniques.', '傳統抹茶茶道需要精確的準備技巧。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Herbal tea', '草本茶', '/ˈhɜːrbəl tiː/', 'Herbal tea blends offer caffeine-free alternatives to traditional teas.', '草本茶混合物提供無咖啡因的傳統茶替代選擇。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Chai tea', '印度香料茶', '/tʃaɪ tiː/', 'Spiced chai tea combines black tea with aromatic spices like cardamom and cinnamon.', '香料印度茶結合了紅茶與豆蔻、肉桂等芳香香料。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Espresso', '義式濃縮咖啡', '/ɪˈspresəʊ/', 'A perfect espresso should have a golden crema on top.', '完美的義式濃縮咖啡頂部應該要有金黃色的咖啡油脂。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Americano', '美式咖啡', '/əˌmerɪˈkɑːnəʊ/', 'I''ll have an Americano with an extra shot of espresso.', '我要一杯美式咖啡，多加一份濃縮咖啡。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Cappuccino', '卡布奇諾', '/ˌkæpʊˈtʃiːnəʊ/', 'The cappuccino here has excellent microfoam texture.', '這裡的卡布奇諾有著極佳的奶泡質地。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Latte', '拿鐵咖啡', '/ˈlɑːteɪ/', 'She ordered a vanilla latte with oat milk instead of regular milk.', '她點了一杯香草拿鐵，用燕麥奶取代一般牛奶。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Macchiato', '瑪奇朵', '/ˌmækɪˈɑːtəʊ/', 'A traditional macchiato is simply espresso with a dollop of foamed milk.', '傳統的瑪奇朵就是濃縮咖啡加上一匙奶泡。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Mocha', '摩卡咖啡', '/ˈməʊkə/', 'The mocha combines the richness of chocolate with coffee perfectly.', '摩卡咖啡完美結合了巧克力的濃郁與咖啡的香醇。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Flat white', '澳式白咖啡', '/flæt waɪt/', 'Flat white originated in Australia and has gained popularity globally.', '澳式白咖啡起源於澳洲，現在在全球都很受歡迎。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Cold brew', '冷萃咖啡', '/kəʊld bruː/', 'Cold brew coffee has a smoother, less acidic taste than iced coffee.', '冷萃咖啡比冰咖啡有著更順滑、酸度更低的口感。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Frappuccino', '星冰樂', '/ˌfræpʊˈtʃiːnəʊ/', 'The caramel frappuccino is their signature blended beverage.', '焦糖星冰樂是他們的招牌調和飲品。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Ristretto', '濃縮義式咖啡', '/rɪˈstretəʊ/', 'Ristretto uses the same amount of coffee but half the water of espresso.', '濃縮義式咖啡使用相同的咖啡量但只用濃縮咖啡一半的水量。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Cortado', '可塔朵', '/kɔːˈtɑːdəʊ/', 'A cortado is equal parts espresso and warm milk without foam.', '可塔朵是等比例的濃縮咖啡和溫牛奶，不加奶泡。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Gibraltar', '直布羅陀咖啡', '/dʒɪˈbrɔːltər/', 'Gibraltar is served in a small glass and similar to cortado.', '直布羅陀咖啡用小玻璃杯盛裝，類似可塔朵。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Affogato', '阿芙佳朵', '/ˌæfəˈɡɑːtəʊ/', 'Affogato is vanilla ice cream "drowned" in hot espresso.', '阿芙佳朵是香草冰淇淋「淹沒」在熱濃縮咖啡中。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Drip coffee', '滴漏咖啡', '/drɪp ˈkɒfi/', 'Drip coffee is brewed by pouring hot water over ground coffee.', '滴漏咖啡是將熱水倒在咖啡粉上沖泡而成。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('French press', '法式濾壓壺', '/frentʃ pres/', 'French press coffee has a full body and rich flavor.', '法式濾壓壺咖啡有著飽滿的醇度和豐富風味。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Pour over', '手沖咖啡', '/pɔːr ˈəʊvər/', 'Pour over method allows precise control over brewing variables.', '手沖咖啡方法允許精確控制沖泡變數。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Red wine', '紅酒', '/red waɪn/', 'This red wine pairs excellently with the grilled steak.', '這款紅酒與烤牛排搭配得非常完美。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
