('Vodka', '伏特加', '/ˈvɒdkə/', 'Premium vodka should be smooth and clean-tasting.', '頂級伏特加應該口感順滑純淨。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Gin', '琴酒', '/dʒɪn/', 'Gin and tonic is a classic British cocktail.', '琴酒通寧水是經典英式雞尾酒。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Rum', '蘭姆酒', '/rʌm/', 'Dark rum adds depth to tropical cocktails.', '深色蘭姆酒為熱帶雞尾酒增添層次。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Brandy', '白蘭地', '/ˈbrændi/', 'Aged brandy is often enjoyed as a digestif after dinner.', '陳年白蘭地常作為餐後酒享用。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
