('Soda', '汽水', '/ˈsəʊdə/', 'I don''t drink soda because it contains too much sugar.', '我不喝汽水因為糖分太高。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Smoothie', '果昔', '/ˈsmuːði/', 'This mango smoothie is incredibly refreshing.', '這杯芒果果昔非常清爽。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
