('Energy drink', '能量飲料', '/ˈenərdʒi drɪŋk/', 'Athletes often consume energy drinks before training.', '運動員經常在訓練前飲用能量飲料。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Sports drink', '運動飲料', '/spɔːts drɪŋk/', 'Sports drinks help replenish electrolytes after exercise.', '運動飲料有助於運動後補充電解質。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Coconut water', '椰子水', '/ˈkəʊkənʌt ˈwɔːtər/', 'Natural coconut water is packed with potassium.', '天然椰子水富含鉀離子。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Milk', '牛奶', '/mɪlk/', 'Whole milk contains more fat than skim milk.', '全脂牛奶比脫脂牛奶含有更多脂肪。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Almond milk', '杏仁奶', '/ˈɑːmənd mɪlk/', 'Almond milk is a popular dairy-free alternative.', '杏仁奶是受歡迎的無乳製品替代品。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Oat milk', '燕麥奶', '/əʊt mɪlk/', 'Oat milk creates excellent foam for coffee drinks.', '燕麥奶能為咖啡飲品製造出色的奶泡。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Soy milk', '豆漿', '/sɔɪ mɪlk/', 'Soy milk is high in protein and calcium.', '豆漿富含蛋白質和鈣質。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Iced tea', '冰茶', '/aɪst tiː/', 'Sweet iced tea is popular in the southern United States.', '甜冰茶在美國南部很受歡迎。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Lemonade', '檸檬水', '/ˌleməˈneɪd/', 'Homemade lemonade tastes much better than store-bought versions.', '自製檸檬水比商店購買的好喝多了。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Hot chocolate', '熱巧克力', '/hɒt ˈtʃɒklət/', 'Hot chocolate with marshmallows is perfect for winter.', '加棉花糖的熱巧克力最適合冬天。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Milkshake', '奶昔', '/ˈmɪlkʃeɪk/', 'The vanilla milkshake here is made with real ice cream.', '這裡的香草奶昔是用真正的冰淇淋製作。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Kombucha', '康普茶', '/kəmˈbuːtʃə/', 'Kombucha is a fermented tea beverage with probiotics.', '康普茶是含有益生菌的發酵茶飲料。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Protein shake', '蛋白質奶昔', '/ˈprəʊtiːn ʃeɪk/', 'Post-workout protein shakes help muscle recovery.', '運動後的蛋白質奶昔有助肌肉恢復。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Milk tea', '奶茶', '/mɪlk tiː/', 'Taiwan-style milk tea is famous for its creamy texture.', '台式奶茶以其濃郁質地而聞名。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Taro milk tea', '芋頭奶茶', '/ˈtɑːrəʊ mɪlk tiː/', 'Taro milk tea has a unique purple color and nutty flavor.', '芋頭奶茶有著獨特的紫色和堅果風味。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Brown sugar milk tea', '黑糖奶茶', '/braʊn ˈʃʊɡər mɪlk tiː/', 'Brown sugar milk tea became a global trend in recent years.', '黑糖奶茶近年來成為全球趨勢。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Fresh fruit tea', '水果茶', '/freʃ fruːt tiː/', 'Fresh fruit tea combines tea with seasonal fruits.', '水果茶結合了茶葉與當季水果。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Wintermelon tea', '冬瓜茶', '/ˈwɪntəmelən tiː/', 'Wintermelon tea is a traditional Taiwanese herbal drink.', '冬瓜茶是台灣傳統的草本飲品。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Grass jelly drink', '仙草茶', '/ɡrɑːs ˈdʒeli drɪŋk/', 'Grass jelly drink is believed to have cooling properties.', '仙草茶被認為有清涼降火的功效。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
