('Lemon tea', '檸檬茶', '/ˈlemən tiː/', 'Hong Kong-style lemon tea is served hot with fresh lemon slices.', '港式檸檬茶是熱飲，配有新鮮檸檬片。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Gong Cha', '貢茶', '/ɡɒŋ tʃɑː/', 'Gong Cha has expanded internationally with over 1,500 stores worldwide.', '貢茶已國際化發展，在全球擁有超過1,500家門市。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Tiger Sugar', '老虎堂', '/ˈtaɪɡər ˈʃʊɡər/', 'Tiger Sugar popularized brown sugar boba tea globally.', '老虎堂在全球推廣了黑糖珍珠奶茶。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('The Alley', '鹿角巷', '/ði ˈæli/', 'The Alley is famous for its Instagram-worthy drinks and aesthetic presentation.', '鹿角巷以其適合拍照的飲品和美學呈現而聞名。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Comebuy', '快可立', '/kʌmˈbaɪ/', 'Comebuy specializes in fresh fruit teas and milk teas.', '快可立專精於新鮮水果茶和奶茶。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Yi Fang Taiwan Fruit Tea', '一芳台灣水果茶', '/jiː fæŋ ˈtaɪwɑːn fruːt tiː/', 'Yi Fang Taiwan Fruit Tea uses traditional Taiwanese tea-making techniques.', '一芳台灣水果茶使用傳統台灣製茶技術。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Milksha', '迷客夏', '/ˈmɪlkʃɑː/', 'Milksha focuses on high-quality milk tea with premium ingredients.', '迷客夏專注於使用優質食材的高品質奶茶。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Presotea', '百世達', '/ˈpresəʊtiː/', 'Presotea is known for its freshly pressed tea concept.', '百世達以其現壓茶概念而聞名。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL),
('Sharetea', '歇腳亭', '/ˈʃeərtiː/', 'Sharetea has become a global ambassador for Taiwanese bubble tea culture.', '歇腳亭已成為台灣珍珠奶茶文化的全球大使。', (SELECT id FROM categories WHERE name = '食物飲品'), NULL);
