('Department store', '百貨公司', '/dɪˈpɑːtmənt stɔː/', 'The department store is having a huge sale this weekend.', '百貨公司這週末有大特價。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Florist', '花店', '/ˈflɒrɪst/', 'I bought roses from the florist for my anniversary.', '我在花店買玫瑰花慶祝週年紀念。', (SELECT id FROM categories WHERE name = '地方'), NULL),
