('Food court', '美食廣場', '/fuːd kɔːt/', 'The shopping mall''s food court offers diverse dining options.', '購物中心的美食廣場提供多樣化的用餐選擇。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Bar', '酒吧', '/bɑː/', 'The hotel bar serves cocktails and light snacks.', '飯店酒吧供應雞尾酒和輕食。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Karaoke', '卡拉OK', '/ˌkæriˈəʊki/', 'We spent the evening singing at the karaoke with friends.', '我們和朋友在卡拉OK度過了一個晚上。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Hotel', '飯店', '/həʊˈtel/', 'We booked a luxury hotel for our anniversary trip.', '我們為週年旅行預訂了豪華飯店。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Motel', '汽車旅館', '/məʊˈtel/', 'The motel along the highway offers convenient parking.', '高速公路沿線的汽車旅館提供便利的停車服務。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Hostel', '青年旅社', '/ˈhɒstəl/', 'Backpackers often stay at a hostel to save money.', '背包客經常住青年旅社來省錢。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Inn', '小旅館', '/ɪn/', 'The charming countryside inn offers a peaceful retreat.', '迷人的鄉村小旅館提供寧靜的度假環境。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Resort', '度假村', '/rɪˈzɔːt/', 'The beach resort includes spa services and water sports.', '海灘度假村包含水療服務和水上運動。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Guest house', '民宿', '/ɡest haʊs/', 'The family-run guest house provides a homely atmosphere.', '家庭經營的民宿提供家庭般的溫馨氛圍。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Bed and breakfast', '含早餐民宿', '/bed ænd ˈbrekfəst/', 'The bed and breakfast serves fresh homemade pastries.', '含早餐民宿提供新鮮的自製糕點。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Tourist information center', '遊客資訊中心', '/ˈtʊərɪst ˌɪnfəˈmeɪʃən ˈsentə/', 'Stop by the tourist information center for maps and brochures.', '到遊客資訊中心拿地圖和宣傳手冊。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Gym', '健身房', '/dʒɪm/', 'I go to the gym three times a week to stay fit.', '我每週去健身房三次保持身材。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Swimming pool', '游泳池', '/ˈswɪmɪŋ puːl/', 'The hotel''s swimming pool is open from 6 AM to 10 PM.', '飯店的游泳池從早上6點開放到晚上10點。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Sports center', '運動中心', '/spɔːts ˈsentə/', 'The local sports center offers basketball and tennis courts.', '當地的運動中心提供籃球場和網球場。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Golf course', '高爾夫球場', '/ɡɒlf kɔːs/', 'The golf course features 18 challenging holes.', '高爾夫球場有18個具挑戰性的球洞。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Tennis court', '網球場', '/ˈtenɪs kɔːt/', 'We reserved the tennis court for this afternoon.', '我們預訂了今天下午的網球場。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Bowling alley', '保齡球館', '/ˈbəʊlɪŋ ˈæli/', 'The bowling alley is a popular weekend destination.', '保齡球館是週末的熱門去處。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Spa', '水療中心', '/spɑː/', 'The luxury spa offers massage and beauty treatments.', '豪華水療中心提供按摩和美容療程。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Fitness center', '健身中心', '/ˈfɪtnəs ˈsentə/', 'The apartment complex includes a modern fitness center.', '公寓大樓包含現代化的健身中心。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Airport', '機場', '/ˈeəpɔːt/', 'The airport shuttle runs every 30 minutes.', '機場接駁車每30分鐘一班。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Train station', '火車站', '/treɪn ˈsteɪʃən/', 'The train station is within walking distance of the hotel.', '火車站在飯店的步行距離內。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Bus terminal', '公車總站', '/bʌs ˈtɜːmɪnəl/', 'Long-distance buses depart from the main bus terminal.', '長途公車從主要的公車總站發車。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Subway station', '地鐵站', '/ˈsʌbweɪ ˈsteɪʃən/', 'The subway station entrance is right across the street.', '地鐵站入口就在街對面。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Port', '港口', '/pɔːt/', 'Cruise ships dock at the port every Tuesday.', '遊輪每週二在港口停靠。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Ferry terminal', '渡輪碼頭', '/ˈferi ˈtɜːmɪnəl/', 'The ferry terminal connects the island to the mainland.', '渡輪碼頭連接島嶼和大陸。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Parking garage', '停車場', '/ˈpɑːkɪŋ ɡəˈrɑːʒ/', 'The downtown parking garage offers hourly rates.', '市中心的停車場提供按小時計費。', (SELECT id FROM categories WHERE name = '地方'), NULL),
('Gas station', '加油站', '/ɡæs ˈsteɪʃən/', 'We need to stop at a gas station before the long drive.', '長途駕駛前我們需要在加油站停一下。', (SELECT id FROM categories WHERE name = '地方'), NULL);
