('become', '變成、成為', '/bɪˈkʌm/', 'She became a successful doctor after years of study.', '經過多年學習，她成為了一名成功的醫生。', (SELECT id FROM categories WHERE name = '動詞'), NULL),
('feel', '感覺、摸起來', '/fiːl/', 'The fabric feels incredibly soft against your skin.', '這布料貼著皮膚感覺非常柔軟。', (SELECT id FROM categories WHERE name = '動詞'), NULL),
('look', '看起來、顯得', '/lʊk/', 'The new building looks modern and impressive.', '這座新建築看起來既現代又令人印象深刻。', (SELECT id FROM categories WHERE name = '動詞'), NULL),
