('sound', '聽起來', '/saʊnd/', 'Your plan sounds practical and well-thought-out.', '你的計劃聽起來很實用且經過深思熟慮。', (SELECT id FROM categories WHERE name = '動詞'), NULL),
('appear', '顯得、似乎', '/əˈpɪə/', 'The professor appears confident about the research results.', '教授對研究結果顯得很有信心。', (SELECT id FROM categories WHERE name = '動詞'), NULL),
('remain', '保持、仍然是', '/rɪˈmeɪn/', 'The mystery remains unsolved despite extensive investigation.', '儘管進行了廣泛調查，這個謎團仍然未解。', (SELECT id FROM categories WHERE name = '動詞'), NULL),
