('far', '遠的', '/fɑːr/', 'The store is far from here.', '商店離這裡很遠。', (SELECT id FROM categories WHERE name = '介係詞'), NULL),
('above', '在...上方', '/əˈbʌv/', 'The bird flies above the tree.', '鳥在樹上方飛翔。', (SELECT id FROM categories WHERE name = '介係詞'), NULL),
