('Heat wave', '熱浪', '/hiːt weɪv/', 'A heat wave is expected to last through the weekend. 
INSERT INTO vocabularies (english, chinese, phonetic, example_en, example_cn, category_id, image) VALUES
('preschool', '學前班、托兒所', '/ˈpriːskuːl/', 'Many parents send their children to preschool before kindergarten.', '許多父母在孩子上幼稚園前先送他們去學前班。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('kindergarten', '幼稚園', '/ˈkɪndərˌɡɑrtən/', 'Children usually attend kindergarten at age five or six.', '孩子通常在五、六歲時上幼稚園。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('elementary school', '小學', '/ˌeləˈmentri skuːl/', 'Elementary school provides the foundation for all future learning.', '小學為未來所有學習奠定基礎。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('primary school', '小學（英式）', '/ˈpraɪmeri skuːl/', 'In the UK, children attend primary school from ages 5 to 11.', '在英國，孩子從5歲到11歲上小學。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('middle school', '中學', '/ˈmɪdl skuːl/', 'Middle school bridges elementary and high school education.', '中學銜接小學和高中教育。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('secondary school', '中學（英式）', '/ˈsekənderi skuːl/', 'Secondary school education typically lasts five years in the UK.', '在英國，中學教育通常持續五年。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('junior high school', '國中', '/ˈdʒuniər haɪ skuːl/', 'Junior high school students are usually 12 to 15 years old.', '國中學生通常是12到15歲。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('senior high school', '高中', '/ˈsinjər haɪ skuːl/', 'Senior high school prepares students for university entrance exams.', '高中為學生準備大學入學考試。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('vocational school', '職業學校', '/voʊˈkeɪʃənl skuːl/', 'Vocational schools offer practical training for specific careers.', '職業學校為特定職業提供實務訓練。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('public school', '公立學校', '/ˈpʌblɪk skuːl/', 'Public schools are funded by the government.', '公立學校由政府資助。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('private school', '私立學校', '/ˈpraɪvət skuːl/', 'Private schools often have smaller class sizes.', '私立學校通常班級規模較小。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('international school', '國際學校', '/ˌɪntərˈnæʃənl skuːl/', 'International schools follow foreign curricula.', '國際學校遵循外國課程。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('boarding school', '寄宿學校', '/ˈbɔrdɪŋ skuːl/', 'Students at boarding schools live on campus.', '寄宿學校的學生住在校園內。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('charter school', '特許學校', '/ˈtʃɑrtər skuːl/', 'Charter schools have more flexibility in their curriculum.', '特許學校在課程設計上有更多彈性。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('alternative school', '另類學校', '/ɔlˈtɜrnətɪv skuːl/', 'Alternative schools offer non-traditional education methods.', '另類學校提供非傳統教育方法。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('online school', '線上學校', '/ˈɔnlaɪn skuːl/', 'Online schools became more popular during the pandemic.', '線上學校在疫情期間變得更受歡迎。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('college', '大學、學院', '/ˈkɑlɪdʒ/', 'She plans to attend college after graduating from high school.', '她計劃高中畢業後上大學。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('university', '大學', '/ˌjunəˈvɜrsəti/', 'National Taiwan University is one of the top universities in Asia.', '台灣大學是亞洲頂尖大學之一。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('graduate school', '研究所', '/ˈɡrædʒuət skuːl/', 'Graduate school provides advanced study beyond the bachelor''s degree.', '研究所提供學士學位之後的進階學習。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('first grade', '一年級', '/fɜrst ɡreɪd/', 'First grade is where students learn basic reading and math skills.', '一年級是學生學習基本閱讀和數學技能的階段。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('freshman', '大一新生、高一新生', '/ˈfreʃmən/', 'As a freshman, she was excited about starting university life.', '作為大一新生，她對開始大學生活感到興奮。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('sophomore', '大二學生、高二學生', '/ˈsɑfəmɔr/', 'Sophomores often feel more confident than in their first year.', '大二學生通常比第一年更有信心。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('junior', '大三學生、高三學生', '/ˈdʒunjər/', 'Junior year is critical for college applications in the US.', '在美國，大三對大學申請至關重要。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('senior', '大四學生、高四學生', '/ˈsinjər/', 'Seniors are busy preparing for graduation and future careers.', '大四學生忙於準備畢業和未來職業。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('student', '學生', '/ˈstudənt/', 'The student raised her hand to ask a question.', '這位學生舉手發問。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('pupil', '小學生', '/ˈpjupəl/', 'Each pupil in the class has their own desk.', '班上每位小學生都有自己的課桌。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('classmate', '同班同學', '/ˈklæsmet/', 'My classmate helped me with the difficult math problem.', '我的同班同學幫我解決了困難的數學題。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('teacher', '老師', '/ˈtitʃər/', 'The teacher explained the lesson very clearly.', '這位老師把課程解釋得非常清楚。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('professor', '教授', '/prəˈfesər/', 'The professor published a research paper last month.', '這位教授上個月發表了一篇研究論文。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('principal', '校長', '/ˈprɪnsəpəl/', 'The principal announced new school policies.', '校長宣布了新的校規。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('dean', '院長、學務長', '/din/', 'The dean of students handles disciplinary matters.', '學務院長處理紀律事務。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('counselor', '輔導老師', '/ˈkaʊnsələr/', 'Students can speak to the counselor about personal problems.', '學生可以向輔導老師談論個人問題。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('librarian', '圖書館員', '/laɪˈbreriən/', 'The librarian helped me find the book I needed.', '圖書館員幫我找到了我需要的書。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('janitor', '清潔工', '/ˈdʒænɪtər/', 'The janitor keeps our school clean and tidy.', '清潔工保持我們學校的整潔。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('secretary', '秘書', '/ˈsekrəteri/', 'The school secretary answered the phone politely.', '學校秘書禮貌地接聽電話。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('school gate', '校門', '/skuːl ɡeɪt/', 'Students must enter through the main school gate.', '學生必須從主校門進入。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('hallway', '走廊', '/ˈhɔlweɪ/', 'Please walk quietly in the hallway during class time.', '上課期間請在走廊安靜走動。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('corridor', '走廊、通道', '/ˈkɔrɪdər/', 'The corridor connects all the classrooms on this floor.', '走廊連接了這層樓所有的教室。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('staircase', '樓梯', '/ˈsterkeɪs/', 'Use the staircase on the left to go to the second floor.', '使用左邊的樓梯到二樓。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('elevator', '電梯', '/ˈeləveɪtər/', 'The elevator is reserved for students with disabilities.', '電梯保留給身障學生使用。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('school store', '福利社', '/skuːl stɔr/', 'The school store sells snacks and school supplies.', '福利社販賣點心和學校用品。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('basketball court', '籃球場', '/ˈbæskɪtˌbɔl kɔrt/', 'The basketball court is available after school for practice.', '籃球場放學後開放練習。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('tennis court', '網球場', '/ˈtenɪs kɔrt/', 'Our school has two outdoor tennis courts.', '我們學校有兩個室外網球場。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('track and field', '田徑場', '/træk ənd fild/', 'The track and field team practices every afternoon.', '田徑隊每天下午練習。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('student activity center', '學生活動中心', '/ˈstudənt ækˈtɪvəti ˈsentər/', 'The student activity center hosts various club meetings.', '學生活動中心舉辦各種社團會議。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('music room', '音樂教室', '/ˈmjuzɪk rum/', 'The music room is equipped with various instruments.', '音樂教室配備各種樂器。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('art room', '美術教室', '/ɑrt rum/', 'Students create paintings and sculptures in the art room.', '學生在美術教室創作繪畫和雕塑。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('language lab', '語言教室', '/ˈlæŋɡwɪdʒ læb/', 'The language lab has headsets for listening practice.', '語言教室有耳機供聽力練習。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('assembly hall', '集會大廳', '/əˈsembli hɔl/', 'The assembly hall can hold the entire student body.', '集會大廳可容納全校學生。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('classroom', '教室', '/ˈklæsrum/', 'We gathered in the classroom for the morning lesson.', '我們在教室裡聚集上早課。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('laboratory', '實驗室', '/ˈlæbrəˌtɔri/', 'The science laboratory is equipped with modern instruments.', '科學實驗室配備了現代化儀器。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('library', '圖書館', '/ˈlaɪˌbreri/', 'Students study quietly in the library.', '學生們在圖書館裡安靜地學習。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('auditorium', '禮堂', '/ˌɔdɪˈtɔriəm/', 'The graduation ceremony was held in the auditorium.', '畢業典禮在禮堂舉行。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('lecture hall', '演講廳', '/ˈlektʃər hɔl/', 'The lecture hall can accommodate 200 students.', '演講廳可容納200名學生。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('computer lab', '電腦教室', '/kəmˈpjutər læb/', 'We have typing class in the computer lab every Tuesday.', '我們每週二在電腦教室上打字課。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('gymnasium', '體育館', '/dʒɪmˈneziəm/', 'The basketball game will be held in the gymnasium.', '籃球比賽將在體育館舉行。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('playground', '操場', '/ˈpleɪgraʊnd/', 'Children play games on the playground during recess.', '孩子們在課間休息時在操場上玩遊戲。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('cafeteria', '自助餐廳', '/ˌkæfəˈtɪriə/', 'The cafeteria serves healthy meals for students.', '自助餐廳為學生提供健康餐點。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('dormitory', '宿舍', '/ˈdɔrmɪˌtɔri/', 'International students live in the dormitory on campus.', '國際學生住在校園內的宿舍。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('dining hall', '餐廳', '/ˈdaɪnɪŋ hɔl/', 'The dining hall serves breakfast from 7 to 9 AM.', '餐廳從早上7點到9點供應早餐。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('sports field', '運動場', '/spɔrts fild/', 'Students practice soccer on the sports field after school.', '學生放學後在運動場練習足球。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('swimming pool', '游泳池', '/ˈswɪmɪŋ pul/', 'The swimming pool is open for students during lunch break.', '游泳池在午休時間對學生開放。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('parking lot', '停車場', '/ˈpɑrkɪŋ lɑt/', 'Teachers park their cars in the parking lot behind the school.', '老師們把車停在學校後面的停車場。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('office', '辦公室', '/ˈɔfɪs/', 'Please go to the principal''s office immediately.', '請立即前往校長辦公室。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('reception', '接待處', '/rɪˈsepʃən/', 'Visitors must register at the reception first.', '訪客必須先在接待處登記。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('nurse''s office', '保健室', '/ˈnɜrsɪz ˈɔfɪs/', 'She went to the nurse''s office because she felt sick.', '她因為身體不適去了保健室。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('faculty lounge', '教職員休息室', '/ˈfækəlti laʊndʒ/', 'Teachers relax in the faculty lounge during breaks.', '老師們在休息時間到教職員休息室放鬆。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('pen', '鋼筆、原子筆', '/pen/', 'Please use a blue pen to fill out the form.', '請用藍色原子筆填寫表格。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('pencil', '鉛筆', '/ˈpensəl/', 'She drew a beautiful picture with her pencil.', '她用鉛筆畫了一幅美麗的圖畫。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('eraser', '橡皮擦', '/ɪˈresər/', 'I need an eraser to correct this mistake.', '我需要橡皮擦來改正這個錯誤。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('highlighter', '螢光筆', '/ˈhaɪˌlaɪtər/', 'Use a highlighter to mark important information.', '用螢光筆標記重要資訊。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('marker', '麥克筆', '/ˈmɑrkər/', 'The teacher wrote on the whiteboard with a marker.', '老師用麥克筆在白板上書寫。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('crayon', '蠟筆', '/ˈkreɪən/', 'Young students use crayons to color their drawings.', '小學生用蠟筆為圖畫上色。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('ruler', '尺', '/ˈrulər/', 'Use a ruler to draw straight lines in geometry class.', '在幾何課中用尺畫直線。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('calculator', '計算機', '/ˈkælkjəˌleɪtər/', 'Students need a calculator for advanced math problems.', '學生需要計算機來解決進階數學問題。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('compass', '圓規', '/ˈkʌmpəs/', 'The compass is essential for drawing perfect circles.', '圓規是畫完美圓形的必需品。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('notebook', '筆記本', '/ˈnotbʊk/', 'I take notes in my notebook during class.', '我在上課時在筆記本上做筆記。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('textbook', '教科書', '/ˈtekstbʊk/', 'We need to buy the textbook for biology class.', '我們需要購買生物課的教科書。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('worksheet', '練習題單', '/ˈwɜrkʃit/', 'Complete the worksheet for homework tonight.', '今晚完成練習題單作為作業。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('paper', '紙張', '/ˈpeɪpər/', 'Please hand in your essays on clean paper.', '請將論文寫在乾淨的紙張上交出。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('backpack', '後背包', '/ˈbækpæk/', 'My backpack is heavy with all these books.', '我的後背包因為所有這些書而很重。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('binder', '活頁夾', '/ˈbaɪndər/', 'Organize your papers in a binder by subject.', '按科目將你的文件整理在活頁夾中。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('folder', '文件夾', '/ˈfoldər/', 'Keep your assignments in this folder.', '將你的作業放在這個文件夾裡。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('locker', '置物櫃', '/ˈlɑkər/', 'I keep my gym clothes in my locker.', '我把體育服放在置物櫃裡。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
