('history', '歷史', '/ˈhɪstəri/', 'Ancient civilizations are covered in history class.', '古代文明在歷史課中涵蓋。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('geography', '地理', '/dʒiˈɑgrəfi/', 'We learned about different continents in geography.', '我們在地理課學習不同的大陸。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
