('chemistry', '化學', '/ˈkemɪstri/', 'Chemistry experiments require safety goggles.', '化學實驗需要戴安全護目鏡。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('physics', '物理', '/ˈfɪzɪks/', 'Physics explains how objects move and interact.', '物理解釋物體如何移動和相互作用。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('biology', '生物', '/baɪˈɑlədʒi/', 'We studied plant cells in biology class yesterday.', '我們昨天在生物課學習植物細胞。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('art', '美術', '/ɑrt/', 'Art class allows students to express their creativity.', '美術課讓學生表達創造力。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('music', '音樂', '/ˈmjuzɪk/', 'The music teacher taught us to play the piano.', '音樂老師教我們彈鋼琴。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
