('economics', '經濟學', '/ˌikəˈnɑmɪks/', 'Economics teaches students about financial systems.', '經濟學教學生有關金融體系的知識。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('philosophy', '哲學', '/fəˈlɑsəfi/', 'Philosophy encourages critical thinking skills.', '哲學培養批判性思維技能。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('assembly', '全校集會', '/əˈsembli/', 'Students gathered in the auditorium for morning assembly.', '學生們聚集在禮堂參加晨間集會。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('field trip', '校外教學', '/fild trɪp/', 'Our class is going on a field trip to the science museum.', '我們班要去科學博物館進行校外教學。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('club activity', '社團活動', '/klʌb ækˈtɪvəti/', 'She participates in various club activities after school.', '她放學後參加各種社團活動。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('sports day', '運動會', '/spɔrts deɪ/', 'Sports day is scheduled for next Friday.', '運動會安排在下週五。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
