('homeroom', '導師時間', '/ˈhomrum/', 'Homeroom starts at 8:00 AM every morning.', '導師時間每天早上8點開始。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('recess', '課間休息', '/ˈrisɛs/', 'Students play outside during recess.', '學生在課間休息時在外面玩耍。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('lunch break', '午休時間', '/lʌntʃ breɪk/', 'The lunch break lasts for one hour.', '午休時間持續一小時。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('detention', '留校察看', '/dɪˈtenʃən/', 'He received detention for being late repeatedly.', '他因為多次遲到而被留校察看。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('take notes', '做筆記', '/teɪk nots/', 'Students should take notes during the lecture.', '學生應該在講課期間做筆記。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('pay attention', '專心、注意', '/peɪ əˈtenʃən/', 'Please pay attention to the safety instructions.', '請注意安全指示。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('raise your hand', '舉手', '/reɪz jər hænd/', 'Raise your hand if you have a question.', '如果有問題請舉手。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('work in pairs', '兩人一組工作', '/wɜrk ɪn perz/', 'Let''s work in pairs for this activity.', '讓我們兩人一組進行這個活動。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('hand in', '繳交', '/hænd ɪn/', 'Don''t forget to hand in your homework tomorrow.', '別忘了明天繳交作業。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('look up', '查找', '/lʊk ʌp/', 'Look up the meaning of this word in the dictionary.', '在字典裡查找這個字的意思。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('turn to page', '翻到某頁', '/tɜrn tu peɪdʒ/', 'Please turn to page 35 in your textbook.', '請翻到課本第35頁。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('read aloud', '大聲朗讀', '/rid əˈlaʊd/', 'Can someone read aloud the first paragraph?', '有人可以大聲朗讀第一段嗎？', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('write down', '寫下', '/raɪt daʊn/', 'Write down the key points from today''s lesson.', '寫下今天課程的重點。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('pair up', '配對、組隊', '/per ʌp/', 'Everyone pair up with a classmate for this exercise.', '每個人都與同學配對做這個練習。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('quiet down', '安靜下來', '/ˈkwaɪət daʊn/', 'Class, please quiet down so we can begin.', '同學們，請安靜下來我們可以開始。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('focus on', '專注於', '/ˈfokəs ɑn/', 'Let''s focus on chapter three today.', '我們今天專注於第三章。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('study for', '為...而學習', '/ˈstʌdi fər/', 'I need to study for the history exam tomorrow.', '我需要為了明天的歷史考試而學習。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('cram for', '臨時抱佛腳', '/kræm fər/', 'Don''t cram for the test at the last minute.', '不要到最後一刻才臨時抱佛腳。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('review material', '複習材料', '/rɪˈvju məˈtɪriəl/', 'We should review material from the entire semester.', '我們應該複習整個學期的材料。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('take an exam', '參加考試', '/teɪk æn ɪgˈzæm/', 'All students must take an exam at the end of the course.', '所有學生必須在課程結束時參加考試。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('sit for a test', '應考', '/sɪt fər ə test/', 'International students will sit for a test next week.', '國際學生下週將應考。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('pass', '及格、通過', '/pæs/', 'I hope I can pass the final exam this semester.', '我希望這學期能通過期末考試。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('fail', '不及格、失敗', '/feɪl/', 'She was worried she might fail the math test.', '她擔心可能會不及格數學考試。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('ace the test', '考得極好', '/eɪs ðə test/', 'He managed to ace the test without much studying.', '他沒怎麼學習就成功考得極好。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('get a grade', '得到成績', '/get ə greɪd/', 'Students will get a grade for their project presentations.', '學生將因專題報告得到成績。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('make the grade', '達到標準', '/meɪk ðə greɪd/', 'Work harder if you want to make the grade.', '如果你想達到標準就要更努力。', (SELECT id FROM categories WHERE name = '學校學習'), NULL),
('score well', '得到好分數', '/skər wel/', 'Practice regularly to score well on standardized tests.', '定期練習以在標準化考試中得到好分數。', (SELECT id FROM categories WHERE name = '學校學習'), NULL);
