('Fact-checker', '事實查核員', '/fækt ˈtʃekə/', 'The fact-checker verified information accuracy for investigative reports.', '該事實查核員為調查報告驗證資訊準確性。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Scriptwriter', '編劇', '/ˈskrɪptˌraɪtə/', 'The scriptwriter created compelling narratives for documentary productions.', '該編劇為紀錄片製作創造引人入勝的敘述。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('News Analyst', '新聞分析師', '/njuːz ˈænəlɪst/', 'The news analyst provided expert commentary on political developments.', '該新聞分析師對政治發展提供專家評論。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Documentary Filmmaker', '紀錄片製作人', '/ˌdɒkjʊˈmentri ˈfɪlmˌmeɪkə/', 'The documentary filmmaker produced award-winning films on environmental issues.', '該紀錄片製作人製作關於環境議題的獲獎影片。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Scientist', '科學家', '/ˈsaɪəntɪst/', 'The scientist conducted groundbreaking research in quantum physics.', '該科學家在量子物理學方面進行突破性研究。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Laboratory Technician', '實驗室技術員', '/ləˈbɒrətri tekˈnɪʃən/', 'The laboratory technician maintained precise experimental conditions for research.', '該實驗室技術員為研究維持精確的實驗條件。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Research Scientist', '研究科學家', '/rɪˈsɜːtʃ ˈsaɪəntɪst/', 'The research scientist published breakthrough findings in renewable energy technology.', '該研究科學家在再生能源技術方面發表突破性研究。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Mechanical Engineer', '機械工程師', '/məˈkænɪkl ˌendʒɪˈnɪə/', 'The mechanical engineer developed advanced robotics systems for manufacturing.', '該機械工程師為製造業開發先進機器人系統。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Electrical Engineer', '電機工程師', '/ɪˈlektrɪkl ˌendʒɪˈnɪə/', 'The electrical engineer designed smart grid systems for sustainable energy distribution.', '該電機工程師設計智慧電網系統進行永續能源配送。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Chemical Engineer', '化學工程師', '/ˈkemɪkl ˌendʒɪˈnɪə/', 'The chemical engineer optimized processes for pharmaceutical manufacturing.', '該化學工程師優化製藥製造流程。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Environmental Engineer', '環境工程師', '/ɪnˌvaɪrənˈmentl ˌendʒɪˈnɪə/', 'The environmental engineer designed sustainable solutions for water treatment systems.', '該環境工程師為水處理系統設計永續解決方案。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Biomedical Engineer', '生物醫學工程師', '/ˌbaɪəʊˈmedɪkl ˌendʒɪˈnɪə/', 'The biomedical engineer developed innovative medical devices for cardiac surgery.', '該生物醫學工程師為心臟手術開發創新醫療設備。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Environmental Scientist', '環境科學家', '/ɪnˌvaɪrənˈmentl ˈsaɪəntɪst/', 'The environmental scientist studied climate change impacts on ecosystem diversity.', '該環境科學家研究氣候變化對生態系統多樣性的影響。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Biologist', '生物學家', '/baɪˈɒlədʒɪst/', 'The biologist discovered new species in unexplored marine environments.', '該生物學家在未開發的海洋環境中發現新物種。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Physicist', '物理學家', '/ˈfɪzɪsɪst/', 'The physicist contributed to breakthrough discoveries in particle physics.', '該物理學家為粒子物理學的突破性發現做出貢獻。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Astronomer', '天文學家', '/əˈstrɒnəmə/', 'The astronomer detected exoplanets using advanced space telescopes.', '該天文學家使用先進太空望遠鏡探測外行星。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Robotics Engineer', '機器人工程師', '/rəʊˈbɒtɪks ˌendʒɪˈnɪə/', 'The robotics engineer created autonomous systems for space exploration.', '該機器人工程師為太空探索創造自主系統。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Quality Assurance Engineer', '品質保證工程師', '/ˈkwɒlɪti əˈʃʊərəns ˌendʒɪˈnɪə/', 'The quality assurance engineer improved manufacturing processes reducing defects by 40%.', '該品質保證工程師改進製造流程，將缺陷率降低40%。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Laboratory Manager', '實驗室經理', '/ləˈbɒrətri ˈmænɪdʒə/', 'The laboratory manager supervised research operations ensuring safety compliance.', '該實驗室經理監督研究操作確保安全合規。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Process Engineer', '製程工程師', '/ˈprəʊses ˌendʒɪˈnɪə/', 'The process engineer optimized production workflows increasing efficiency by 25%.', '該製程工程師優化生產工作流程，將效率提升25%。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Aerospace Engineer', '航太工程師', '/ˈeərəspeɪs ˌendʒɪˈnɪə/', 'The aerospace engineer contributed to successful satellite launch missions.', '該航太工程師為成功的衛星發射任務做出貢獻。', (SELECT id FROM categories WHERE name = '職業'), NULL),
('Materials Scientist', '材料科學家', '/məˈtɪəriəlz ˈsaɪəntɪst/', 'The materials scientist discovered new alloys with superior strength properties.', '該材料科學家發現具有優異強度特性的新合金。', (SELECT id FROM categories WHERE name = '職業'), NULL);
INSERT INTO vocabularies (english, chinese, phonetic, example_en, example_cn, category_id, image) VALUES
('Christmas', '聖誕節', '/ˈkrɪsməs/', 'Christmas is in December.', '聖誕節在十二月。', (SELECT id FROM categories WHERE name = '節慶'), NULL),
('Halloween', '萬聖節', '/ˌhæloʊˈiːn/', 'Children dress up for Halloween.', '小孩為萬聖節打扮。', (SELECT id FROM categories WHERE name = '節慶'), NULL),
('birthday', '生日', '/ˈbɜːrθdeɪ/', 'Today is my birthday.', '今天是我的生日。', (SELECT id FROM categories WHERE name = '節慶'), NULL),
('party', '派對', '/ˈpɑːrti/', 'We have a party at home.', '我們在家辦派對。', (SELECT id FROM categories WHERE name = '節慶'), NULL),
('gift', '禮物', '/ɡɪft/', 'I give you a gift.', '我給你一個禮物。', (SELECT id FROM categories WHERE name = '節慶'), NULL),
('cake', '蛋糕', '/keɪk/', 'The birthday cake is sweet.', '生日蛋糕很甜。', (SELECT id FROM categories WHERE name = '節慶'), NULL),
('card', '卡片', '/kɑːrd/', 'I make a card for mother.', '我為媽媽做一張卡片。', (SELECT id FROM categories WHERE name = '節慶'), NULL),
('celebration', '慶祝', '/ˌseləˈbreɪʃən/', 'The celebration is wonderful.', '慶祝活動很棒。', (SELECT id FROM categories WHERE name = '節慶'), NULL),
('festival', '節日', '/ˈfestɪvəl/', 'Spring festival is important.', '春節很重要。', (SELECT id FROM categories WHERE name = '節慶'), NULL),
('holiday', '假日', '/ˈhɑːlədeɪ/', 'Summer holiday is fun.', '暑假很有趣。', (SELECT id FROM categories WHERE name = '節慶'), NULL);
INSERT INTO vocabularies (english, chinese, phonetic, example_en, example_cn, category_id, image) VALUES
('Happy', '快樂的、高興的', '/ˈhæpi/', 'I feel happy when I spend time with my family.', '當我和家人相處時感到快樂。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Joyful', '充滿喜悅的', '/ˈdʒɔɪfəl/', 'The wedding was a joyful celebration for everyone.', '這場婚禮對每個人來說都是充滿喜悅的慶祝。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Cheerful', '愉快的、開朗的', '/ˈtʃɪrfəl/', 'She maintained a cheerful attitude despite the challenges.', '儘管面臨挑戰，她仍保持愉快的態度。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Delighted', '欣喜的、高興的', '/dɪˈlaɪtɪd/', 'We were delighted to hear about your promotion.', '聽到你升職的消息我們很欣喜。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Ecstatic', '狂喜的、欣喜若狂的', '/ɪkˈstætɪk/', 'The fans were ecstatic when their team won the championship.', '當球隊贏得冠軍時，球迷們欣喜若狂。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Euphoric', '極度興奮的、陶醉的', '/juˈfɔrɪk/', 'The runner felt euphoric after completing the marathon.', '跑者完成馬拉松後感到極度興奮。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Content', '滿足的、知足的', '/kənˈtent/', 'After a good meal, I feel perfectly content.', '享用美食後，我感到非常滿足。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Pleased', '高興的、滿意的', '/pliːzd/', 'The teacher was pleased with the students'' progress.', '老師對學生們的進步感到高興。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Elated', '興奮的、得意洋洋的', '/ɪˈleɪtɪd/', 'She was elated when she received the scholarship.', '收到獎學金時她興奮不已。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Thrilled', '非常興奮的、激動的', '/θrɪld/', 'The children were thrilled to visit the amusement park.', '孩子們對去遊樂園感到非常興奮。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Overjoyed', '狂喜的、極度開心的', '/ˌoʊvərˈdʒɔɪd/', 'The parents were overjoyed when their son graduated.', '兒子畢業時父母狂喜不已。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Blissful', '極樂的、幸福的', '/ˈblɪsfəl/', 'They spent a blissful honeymoon in Hawaii.', '他們在夏威夷度過了幸福的蜜月。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Buoyant', '樂觀的、振奮的', '/ˈbɔɪənt/', 'Despite the setback, her mood remained buoyant.', '儘管遭遇挫折，她的心情依然振奮。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Upbeat', '樂觀的、積極的', '/ˈʌpbiːt/', 'His upbeat personality lifts everyone''s spirits.', '他樂觀的個性提振了每個人的精神。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Exhilarated', '興奮的、振奮的', '/ɪɡˈzɪləreɪtɪd/', 'I felt exhilarated after the roller coaster ride.', '坐完雲霄飛車後我感到非常興奮。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Gleeful', '歡欣的、高興的', '/ˈɡliːfəl/', 'The children were gleeful about the snow day.', '孩子們對雪假感到歡欣。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Jubilant', '歡欣鼓舞的、喜氣洋洋的', '/ˈdʒuːbɪlənt/', 'The crowd was jubilant after the victory.', '勝利後群眾歡欣鼓舞。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Exuberant', '興高采烈的、精力充沛的', '/ɪɡˈzuːbərənt/', 'Her exuberant personality makes her popular.', '她興高采烈的個性讓她很受歡迎。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Radiant', '容光煥發的、喜悅的', '/ˈreɪdiənt/', 'The bride looked absolutely radiant on her wedding day.', '新娘在婚禮當天容光煥發。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Optimistic', '樂觀的、積極向上的', '/ˌɑːptɪˈmɪstɪk/', 'She remains optimistic about the future.', '她對未來保持樂觀。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Sad', '悲傷的、難過的', '/sæd/', 'I felt sad when my best friend moved away.', '當我最好的朋友搬走時，我感到悲傷。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Depressed', '沮喪的、憂鬱的', '/dɪˈprest/', 'After losing the job, he became depressed for weeks.', '失業後，他沮喪了好幾週。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Melancholy', '憂鬱的、憂愁的', '/ˈmelənkɒli/', 'The rainy weather puts me in a melancholy mood.', '雨天讓我心情憂鬱。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Angry', '生氣的、憤怒的', '/ˈæŋɡri/', 'She was angry about the unfair treatment at work.', '她對工作中的不公平待遇感到憤怒。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Furious', '狂怒的、暴怒的', '/ˈfjʊriəs/', 'The customer was furious about the poor service.', '顧客對糟糕的服務感到狂怒。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Frustrated', '沮喪的、挫敗的', '/ˈfrʌstreɪtɪd/', 'Students often feel frustrated when learning difficult concepts.', '學生在學習困難概念時常感到挫敗。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Anxious', '焦慮的、不安的', '/ˈæŋkʃəs/', 'I always feel anxious before important presentations.', '重要簡報前我總是感到焦慮。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Worried', '擔心的、憂慮的', '/ˈwʌrid/', 'Parents are naturally worried about their children''s safety.', '父母天性會擔心孩子的安全。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Devastated', '極度沮喪的、心碎的', '/ˈdevəsteɪtɪd/', 'She was devastated by the news of her father''s death.', '父親去世的消息讓她心碎。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Heartbroken', '心碎的、傷心欲絕的', '/ˈhɑːrtbroʊkən/', 'He was heartbroken when his girlfriend left him.', '女友離開時他心碎了。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Miserable', '痛苦的、悲慘的', '/ˈmɪzərəbəl/', 'The flu made me feel absolutely miserable.', '流感讓我感到非常痛苦。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Despondent', '沮喪的、意志消沉的', '/dɪˈspɑːndənt/', 'After failing the exam, she became despondent.', '考試失敗後，她變得意志消沉。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Irritated', '惱怒的、煩躁的', '/ˈɪrɪteɪtɪd/', 'I''m irritated by the constant noise from construction.', '建築工地的持續噪音讓我煩躁。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Annoyed', '煩惱的、惱火的', '/əˈnɔɪd/', 'She was annoyed by his constant interruptions.', '他不斷的打斷讓她很煩惱。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Hostile', '敵對的、有敵意的', '/ˈhɑːstəl/', 'The crowd became hostile toward the referee.', '群眾對裁判變得有敵意。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Resentful', '憤恨的、怨恨的', '/rɪˈzentfəl/', 'He felt resentful about being passed over for promotion.', '錯失升職機會讓他感到憤恨。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Bitter', '痛苦的、怨恨的', '/ˈbɪtər/', 'She remained bitter about the divorce years later.', '多年後她對離婚仍然感到痛苦。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Gloomy', '憂鬱的、陰沉的', '/ˈɡluːmi/', 'The bad weather made everyone feel gloomy.', '糟糕的天氣讓每個人都感到憂鬱。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Dejected', '沮喪的、失望的', '/dɪˈdʒektɪd/', 'The team looked dejected after losing the championship.', '輸掉冠軍賽後球隊看起來很沮喪。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Distraught', '心煩意亂的、極度不安的', '/dɪˈstrɔːt/', 'She was distraught when her pet went missing.', '寵物失蹤時她心煩意亂。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Agitated', '激動的、焦躁不安的', '/ˈædʒɪteɪtɪd/', 'He became agitated when the meeting was delayed.', '會議延期時他變得焦躁不安。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Enraged', '憤怒的、暴怒的', '/ɪnˈreɪdʒd/', 'The unfair decision left her enraged.', '不公平的決定讓她憤怒。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Livid', '極其憤怒的、氣得發青的', '/ˈlɪvɪd/', 'She was livid when she discovered the betrayal.', '發現背叛時她氣得發青。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Mortified', '極度羞愧的、窘迫的', '/ˈmɔːrtɪfaɪd/', 'I was mortified when I tripped in front of everyone.', '在大家面前跌倒讓我極度羞愧。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Calm', '平靜的、冷靜的', '/kɑːm/', 'The meditation helped me feel calm and centered.', '冥想幫助我感到平靜和專注。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Confused', '困惑的、迷惑的', '/kənˈfjuːzd/', 'I was confused by the complex instructions.', '我被複雜的指示搞得困惑不已。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Nostalgic', '懷舊的、思鄉的', '/nɒˈstældʒɪk/', 'Looking at old photos makes me feel nostalgic.', '看老照片讓我感到懷舊。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Indifferent', '冷漠的、無所謂的', '/ɪnˈdɪfərənt/', 'He seemed indifferent to the criticism.', '他對批評似乎很冷漠。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Curious', '好奇的、求知的', '/ˈkjʊriəs/', 'Children are naturally curious about the world around them.', '孩子們天性對周圍的世界感到好奇。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Ambivalent', '矛盾的、猶豫不決的', '/æmˈbɪvələnt/', 'She felt ambivalent about accepting the job offer.', '她對接受這份工作邀請感到矛盾。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Serene', '寧靜的、安詳的', '/səˈriːn/', 'The lake looked perfectly serene in the morning light.', '湖水在晨光中顯得非常寧靜。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Overwhelmed', '不知所措的、被壓垮的', '/ˌoʊvərˈwelmd/', 'I feel overwhelmed by all the responsibilities.', '所有的責任讓我感到不知所措。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Perplexed', '困惑的、不解的', '/pərˈplekst/', 'She was perplexed by his sudden change in behavior.', '他行為的突然改變讓她困惑不解。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Contemplative', '沉思的、思考的', '/kənˈtemplətɪv/', 'He was in a contemplative mood after reading the book.', '讀完書後他陷入沉思。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Apathetic', '冷漠的、無感情的', '/ˌæpəˈθetɪk/', 'Students seemed apathetic about the upcoming election.', '學生們對即將到來的選舉似乎很冷漠。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Pensive', '沉思的、憂慮的', '/ˈpensɪv/', 'She had a pensive expression while walking alone.', '獨自走路時她露出沉思的表情。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Restless', '不安的、焦躁的', '/ˈrestləs/', 'I feel restless when I have nothing to do.', '無事可做時我感到焦躁不安。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Skeptical', '懷疑的、多疑的', '/ˈskeptɪkəl/', 'She was skeptical about the new treatment''s effectiveness.', '她對新療法的效果持懷疑態度。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Tranquil', '寧靜的、安靜的', '/ˈtræŋkwɪl/', 'The garden provides a tranquil escape from city life.', '花園提供了遠離城市生活的寧靜空間。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Uneasy', '不安的、不自在的', '/ʌnˈiːzi/', 'I felt uneasy about the stranger following me.', '陌生人跟蹤讓我感到不安。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Wistful', '惆悵的、思念的', '/ˈwɪstfəl/', 'She had a wistful look when talking about her childhood.', '談到童年時她露出惆悵的神色。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Neutral', '中性的、不偏不倚的', '/ˈnuːtrəl/', 'He tried to remain neutral during the argument.', '爭論期間他努力保持中性。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Mellow', '平和的、溫和的', '/ˈmeloʊ/', 'The wine made him feel mellow and relaxed.', '酒讓他感到平和放鬆。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Reluctant', '不情願的、勉強的', '/rɪˈlʌktənt/', 'She was reluctant to share her personal story.', '她不情願分享自己的個人故事。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Stoic', '堅忍的、不動聲色的', '/ˈstoʊɪk/', 'He remained stoic despite the tragedy.', '儘管遭遇悲劇，他仍然堅忍不拔。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Whimsical', '異想天開的、古怪的', '/ˈwɪmzɪkəl/', 'Her whimsical sense of humor brightened everyone''s day.', '她異想天開的幽默感照亮了每個人的一天。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Vulnerable', '脆弱的、易受傷的', '/ˈvʌlnərəbəl/', 'Opening up made her feel vulnerable but authentic.', '敞開心扉讓她感到脆弱但真實。', (SELECT id FROM categories WHERE name = '情感思想'), NULL),
('Reflective', '深思的、反思的', '/rɪˈflektɪv/', 'He was in a reflective mood after the conversation.', '對話後他陷入深思。', (SELECT id FROM categories WHERE name = '情感思想'), NULL);
INSERT INTO vocabularies (english, chinese, phonetic, example_en, example_cn, category_id, image) VALUES
('Mother', '母親', '/ˈmʌðər/', 'My mother works as a nurse in the local hospital.', '我的母親在當地醫院擔任護士。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Father', '父親', '/ˈfɑːðər/', 'My father has been teaching mathematics for over twenty years.', '我的父親教數學超過二十年了。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Son', '兒子', '/sʌn/', 'Their eldest son is currently studying abroad in Canada.', '他們的長子目前在加拿大留學。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Daughter', '女兒', '/ˈdɔːtər/', 'Their daughter just graduated from medical school.', '他們的女兒剛從醫學院畢業。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Brother', '兄弟', '/ˈbrʌðər/', 'My brother and I share many common interests.', '我的兄弟和我有許多共同興趣。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Sister', '姊妹', '/ˈsɪstər/', 'My sister is my closest confidant.', '我的姊妹是我最親密的知己。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Husband', '丈夫', '/ˈhʌzbənd/', 'Her husband supports her career ambitions completely.', '她的丈夫完全支持她的職業理想。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Wife', '妻子', '/waɪf/', 'His wife is a successful entrepreneur.', '他的妻子是一位成功的企業家。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Grandparent', '祖父母/外祖父母', '/ˈɡrændˌperənt/', 'My grandparents raised me with traditional values.&nbsp;', '我的祖父母用傳統價值觀養育我。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Great-grandparent', '曾祖父母', '/ɡreɪt ˈɡrændˌperənt/', 'I was fortunate to know my great-grandparents personally.&nbsp;', '我很幸運能親自認識我的曾祖父母。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Grandchild', '孫子/孫女', '/ˈɡrændˌtʃaɪld/', 'Their grandchildren visit every weekend.', '他們的孫子女每個週末都會來拜訪。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Great-grandchild', '曾孫', '/ɡreɪt ˈɡrændˌtʃaɪld/', 'She lived to see her great-grandchildren grow up.&nbsp;', '她活著看到她的曾孫長大。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Aunt', '姑姑/阿姨', '/ænt/', 'My aunt has always been like a second mother to me.', '我的姑姑對我來說一直像第二個母親。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Uncle', '叔叔/伯伯/舅舅', '/ˈʌŋkəl/', 'My uncle tells the best stories at family dinners.', '我的叔叔在家庭聚餐時說最好聽的故事。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Cousin', '表兄弟姊妹/堂兄弟姊妹', '/ˈkʌzən/', 'My cousins and I grew up together like siblings.', '我的表兄弟姊妹和我一起長大，就像兄弟姊妹一樣。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Nephew', '侄子/外甥', '/ˈnefju/', 'My nephew is extremely talented in music.', '我的侄子在音樂方面非常有天賦。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Niece', '侄女/外甥女', '/niːs/', 'My niece just won a scholarship to university.', '我的侄女剛獲得大學獎學金。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Stepmother', '繼母', '/ˈstepˌmʌðər/', 'My stepmother has been very kind and supportive.', '我的繼母一直很善良且支持我。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Stepfather', '繼父', '/ˈstepˌfɑːðər/', 'My stepfather married my mother when I was ten.', '我的繼父在我十歲時與我母親結婚。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Stepbrother', '繼兄弟', '/ˈstepˌbrʌðər/', 'My stepbrother and I get along very well.', '我的繼兄弟和我相處得很好。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Stepsister', '繼姊妹', '/ˈstepˌsɪstər/', 'My stepsister introduced me to her circle of friends.', '我的繼姊妹把我介紹給她的朋友圈。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Half-brother', '同父異母/同母異父兄弟', '/hæf ˈbrʌðər/', 'My half-brother lives with his mother most of the time.&nbsp;', '我的同父異母兄弟大部分時間和他母親住在一起。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Half-sister', '同父異母/同母異父姊妹', '/hæf ˈsɪstər/', 'Despite being half-sisters, we share a strong bond.', '儘管是同父異母姊妹，我們有很強的情感聯繫。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Son-in-law', '女婿', '/sʌn ɪn lɔː/', 'Their son-in-law is a respected doctor.&nbsp;', '他們的女婿是一位受人尊敬的醫生。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Daughter-in-law', '媳婦', '/ˈdɔːtər ɪn lɔː/', 'The daughter-in-law fits perfectly into our family.&nbsp;', '這位媳婦完美地融入了我們的家庭。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Mother-in-law', '岳母/婆婆', '/ˈmʌðər ɪn lɔː/', 'My mother-in-law gives excellent cooking advice.', '我的岳母給予很好的烹飪建議。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Father-in-law', '岳父/公公', '/ˈfɑːðər ɪn lɔː/', 'My father-in-law and I enjoy fishing together.', '我的岳父和我喜歡一起釣魚。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Sister-in-law', '嫂子/弟媳/姊夫的姊妹', '/ˈsɪstər ɪn lɔː/', 'My sister-in-law is also my best friend.', '我的嫂子也是我最好的朋友。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Brother-in-law', '姊夫/妹夫/配偶的兄弟', '/ˈbrʌðər ɪn lɔː/', 'My brother-in-law works in the same industry as I do.', '我的姊夫和我在同一個行業工作。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Stepparent', '繼父母', '/ˈstepˌperənt/', 'Having a stepparent can provide additional support.', '有繼父母可以提供額外的支持。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Stepsibling', '繼兄弟姊妹', '/ˈstepˌsɪblɪŋ/', 'My stepsiblings and I share holiday traditions.', '我的繼兄弟姊妹和我分享節日傳統。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Adopted child', '被收養的孩子', '/əˈdɑːptɪd tʃaɪld/', 'Their adopted child brings immense joy to the family.', '他們的養子為家庭帶來巨大的快樂。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Adoptive parent', '養父母', '/əˈdɑːptɪv ˈperənt/', 'Adoptive parents provide loving homes for children in need.', '養父母為有需要的孩子提供充滿愛的家庭。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Foster parent', '寄養父母', '/ˈfɔːstər ˈperənt/', 'Foster parents require special training and certification.', '寄養父母需要特殊訓練和認證。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Foster child', '寄養兒童', '/ˈfɔːstər tʃaɪld/', 'The foster child adapted well to the new environment.', '寄養兒童很好地適應了新環境。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Immediate family', '直系親屬', '/ɪˈmiːdiət ˈfæməli/', 'My immediate family consists of my parents, my younger sister, and myself.', '我的直系親屬包括我的父母、妹妹和我自己。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Spouse', '配偶', '/spaʊs/', 'Modern couples often discuss career priorities with their spouse before making major decisions.', '現代夫妻在做重大決定前經常與配偶討論職業優先順序。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Siblings', '兄弟姊妹', '/ˈsɪblɪŋz/', 'Research shows that children with siblings tend to develop better social skills.', '研究顯示有兄弟姊妹的孩子往往發展出更好的社交技能。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Offspring', '後代、子嗣', '/ˈɔːfˌsprɪŋ/', 'Parents invest considerable resources in their offspring''s education.', '父母在其後代的教育上投入相當多的資源。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Ancestor', '祖先', '/ˈænsestər/', 'Many families maintain traditions passed down from their ancestors.', '許多家庭維持著從祖先傳下來的傳統。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Descendant', '後裔', '/dɪˈsendənt/', 'She is a direct descendant of a famous poet.', '她是一位著名詩人的直系後裔。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Extended family', '大家庭、擴展家庭', '/ɪkˈstendɪd ˈfæməli/', 'In many cultures, extended family members play crucial roles in child-rearing.', '在許多文化中，大家庭成員在育兒方面扮演重要角色。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('In-laws', '姻親', '/ˈɪn lɔːz/', 'Building good relationships with in-laws can strengthen family bonds.', '與姻親建立良好關係能加強家庭聯繫。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Breadwinner', '養家糊口的人', '/ˈbredˌwɪnər/', 'In modern families, both parents often serve as breadwinners.', '在現代家庭中，父母雙方通常都是養家糊口的人。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Caregiver', '照護者', '/ˈkerˌɡɪvər/', 'Caregivers play essential roles in supporting elderly family members.', '照護者在支持年長家庭成員方面扮演重要角色。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Guardian', '監護人', '/ˈɡɑːrdiən/', 'The court appointed her aunt as the child''s legal guardian.', '法院指定她的阿姨為孩子的法定監護人。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Next of kin', '最近親屬', '/nekst əv kɪn/', 'Please provide your next of kin for emergency contact purposes.', '請提供您的最近親屬作為緊急聯絡人。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Heir', '繼承人', '/er/', 'The eldest son is traditionally the heir to the family business.', '長子傳統上是家族企業的繼承人。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Nuclear family', '核心家庭', '/ˈnuːkliər ˈfæməli/', 'The traditional nuclear family model is evolving in response to changing social dynamics.', '傳統的核心家庭模式正因應變化的社會動態而演進。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Single-parent household', '單親家庭', '/ˈsɪŋɡəl ˈperənt ˈhaʊshoʊld/', 'Single-parent households face unique challenges in balancing work and childcare.', '單親家庭在平衡工作和育兒方面面臨獨特挑戰。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Blended family', '重組家庭', '/ˈblendɪd ˈfæməli/', 'Blended families require patience and understanding to create harmonious relationships.', '重組家庭需要耐心和理解來創造和諧的關係。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Childless couple', '無子女夫妻', '/ˈtʃaɪldləs ˈkʌpəl/', 'The number of childless couples is increasing in developed countries.', '已開發國家中無子女夫妻的數量正在增加。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Multi-generational household', '多代同堂家庭', '/ˈmʌlti ˌdʒenəˈreɪʃənəl ˈhaʊshoʊld/', 'Multi-generational households are common in many Asian cultures.', '多代同堂家庭在許多亞洲文化中很常見。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Foster family', '寄養家庭', '/ˈfɔːstər ˈfæməli/', 'Foster families provide temporary care for children in need.', '寄養家庭為有需要的兒童提供臨時照護。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Adoptive family', '收養家庭', '/əˈdɑːptɪv ˈfæməli/', 'Adoptive families go through extensive screening processes.', '收養家庭需要經過廣泛的審查程序。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Broken home', '破碎家庭', '/ˈbroʊkən hoʊm/', 'Children from broken homes may face emotional challenges.', '來自破碎家庭的孩子可能面臨情感挑戰。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Single-child family', '獨生子女家庭', '/ˈsɪŋɡəl tʃaɪld ˈfæməli/', 'Single-child families are increasingly common in urban areas.', '獨生子女家庭在城市地區越來越常見。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Large family', '大家庭', '/lɑːrdʒ ˈfæməli/', 'Managing a large family requires excellent organizational skills.', '管理大家庭需要出色的組織能力。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Patriarchal family', '父權家庭', '/ˌpeɪtriˈɑːrkəl ˈfæməli/', 'Traditional patriarchal families are led by the eldest male.', '傳統的父權家庭由年長男性領導。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Matriarchal family', '母權家庭', '/ˌmeɪtriˈɑːrkəl ˈfæməli/', 'Some cultures feature matriarchal families where women hold authority.', '某些文化以母權家庭為特色，女性擁有權威。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Close-knit', '關係緊密的', '/kloʊs nɪt/', 'We''re a close-knit family who supports each other through thick and thin.', '我們是一個關係緊密的家庭，彼此患難與共。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Estranged', '疏遠的、關係惡化的', '/ɪˈstreɪndʒd/', 'Unfortunately, he became estranged from his siblings after the inheritance dispute.&nbsp;', '不幸的是，在遺產糾紛後，他與兄弟姊妹疏遠了。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Harmonious', '和諧的', '/hɑːrˈmoʊniəs/', 'They maintain a harmonious relationship despite their different personalities.', '儘管性格不同，他們仍保持和諧的關係。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Dysfunctional', '功能失調的', '/dɪsˈfʌŋkʃənəl/', 'Children from dysfunctional families may require additional psychological support.', '來自功能失調家庭的兒童可能需要額外的心理支持。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Protective', '保護性的', '/prəˈtektɪv/', 'Asian parents are often described as being protective of their children''s future.', '亞洲父母經常被描述為對子女的未來具有保護性。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Supportive', '支持的', '/səˈpɔːrtɪv/', 'Having supportive family members significantly impacts one''s mental health.', '擁有支持性的家庭成員對心理健康有重大影響。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Nurturing', '養育的、關愛的', '/ˈnɜːrtʃərɪŋ/', 'A nurturing environment helps children develop confidence.', '養育性的環境幫助孩子培養自信心。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Authoritarian', '權威主義的', '/əˌθɔːrəˈteriən/', 'Authoritarian parents tend to have strict rules and high expectations.', '權威主義的父母往往有嚴格的規則和高期望。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Permissive', '寬容的、放任的', '/pərˈmɪsɪv/', 'Permissive parenting styles allow children more freedom to make decisions.', '寬容的教養方式讓孩子有更多自由做決定。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Overprotective', '過度保護的', '/ˌoʊvərprəˈtektɪv/', 'Overprotective parents may hinder their children''s independence.', '過度保護的父母可能阻礙孩子的獨立性。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Neglectful', '疏忽的', '/nɪˈɡlektfəl/', 'Neglectful parenting can lead to behavioral issues in children.', '疏忽的教養可能導致孩子出現行為問題。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Traditional', '傳統的', '/trəˈdɪʃənəl/', 'Traditional families often emphasize respect for elders.', '傳統的家庭通常強調尊敬長輩。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Progressive', '進步的', '/prəˈɡresɪv/', 'Progressive families embrace gender equality in household duties.', '進步的家庭在家務分工上擁抱性別平等。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Upbringing', '教養、成長環境', '/ˈʌpˌbrɪŋɪŋ/', 'My upbringing in a multicultural family shaped my worldview.', '我在多元文化家庭的教養塑造了我的世界觀。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Child-rearing', '育兒', '/tʃaɪld ˈrɪrɪŋ/', 'Modern child-rearing practices emphasize emotional intelligence.', '現代育兒實踐強調情緒智能。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Family reunion', '家庭聚會', '/ˈfæməli riˈjuːnjən/', 'Annual family reunions help maintain strong family bonds.', '年度家庭聚會有助於維持牢固的家庭關係。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Heritage', '傳承、遺產', '/ˈherɪtɪdʒ/', 'Preserving family heritage is important for future generations.', '保存家庭傳承對後代很重要。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Legacy', '遺產、傳承', '/ˈleɡəsi/', 'Long-term impact: "Parents hope to leave a positive legacy for their children."', '父母希望為孩子留下正面的傳承。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Empty nest syndrome', '空巢症候群', '/ˈempti nest ˈsɪndroʊm/', 'Many parents experience empty nest syndrome when children leave home.', '許多父母在孩子離家時會經歷空巢症候群。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Coming of age', '成年、成人禮', '/ˈkʌmɪŋ əv eɪdʒ/', 'Coming of age ceremonies mark the transition to adulthood.', '成人禮標誌著向成年期的過渡。', (SELECT id FROM categories WHERE name = '家庭'), NULL),
('Family outing', '家庭出遊', '/ˈfæməli ˈaʊtɪŋ/', 'Regular family outings strengthen relationships and create memories.', '定期家庭出遊加強關係並創造回憶。', (SELECT id FROM categories WHERE name = '家庭'), NULL);
INSERT INTO vocabularies (english, chinese, phonetic, example_en, example_cn, category_id, grade, image) VALUES
